// 273 câu hỏi trắc nghiệm - Trưởng Kíp Trạm Điện (TT05 & TT06/2025/TT-BCT)
// Đáp án: A=0, B=1, C=2, D=3
const QUESTIONS = [
{id:1,q:"Theo Thông tư 06/2025/TT-BCT: Thời gian đào tạo Điều độ viên miền:",opts:["ít nhất 06 tháng.","ít nhất 12 tháng.","ít nhất 18 tháng.","ít nhất 24 tháng."],ans:2,explain:"TT06 quy định thời gian đào tạo Điều độ viên miền ít nhất 18 tháng."},
{id:2,q:"Theo TT06/2025/TT-BCT: Phiếu thao tác không được hủy trong trường hợp nào?",opts:["Thao tác có xảy ra sự cố hoặc tai nạn","Thao tác đóng điện công trình mới","Thao tác xử lý sự cố","Không quy định"],ans:0,explain:"Phiếu thao tác không được hủy khi có xảy ra sự cố hoặc tai nạn để phục vụ điều tra."},
{id:3,q:"Theo TT06/2025/TT-BCT: Sau khi thao tác máy cắt, nếu sau đó có thao tác tại chỗ dao cách ly hai phía, nhân viên vận hành phải:",opts:["Kiểm tra trạng thái máy cắt theo chỉ thị tín hiệu tại phòng điều khiển và khoá mạch điều khiển","Kiểm tra chỉ thị tại chỗ trạng thái","Kiểm tra chỉ thị tại chỗ trạng thái và khoá mạch điều khiển của máy cắt.","A hoặc C đều đúng"],ans:3,explain:"Phương án D (A hoặc C) là đúng theo quy định TT06."},
{id:4,q:"Theo TT06/2025/TT-BCT, nhân viên vận hành cấp dưới trực tiếp của Điều độ viên miền là ai:",opts:["Điều độ viên phân phối tỉnh","Điều độ viên phân phối quận, huyện","Nhân viên trực thao tác lưu động","Cả 3 đáp án trên đều sai"],ans:0,explain:"NVVH cấp dưới trực tiếp của Điều độ viên miền là Điều độ viên phân phối tỉnh."},
{id:5,q:"Theo TT06/2025/TT-BCT, Đơn vị quản lý vận hành phải gửi Báo cáo sự cố cho Cấp điều độ có quyền điều khiển:",opts:["Ngay sau khi xử lý xong sự cố.","Trong vòng 24 giờ kể từ khi sự cố xảy ra.","Trong vòng 48 giờ kể từ khi sự cố xảy ra.","Không cần gửi báo cáo nếu đã báo cáo qua điện thoại"],ans:1,explain:"TT06 quy định gửi báo cáo sự cố trong vòng 24 giờ kể từ khi sự cố xảy ra."},
{id:6,q:"Theo TT06/2025/TT-BCT, Cấp Điều độ Quốc gia có trách nhiệm:",opts:["Lập Phương án khởi động đen và khôi phục hệ thống điện quốc gia có cấp điện áp từ 220kV","Chỉ huy khởi động đen và khôi phục hệ thống điện có cấp điện áp 500kV","Phê duyệt Phương án khởi động đen và khôi phục hệ thống điện miền có cấp điện áp 110kV","Đáp án A, B, C"],ans:3,explain:"Cấp Điều độ Quốc gia có cả 3 trách nhiệm A, B, C."},
{id:7,q:"Theo TT06/2025/TT-BCT, máy biến áp dầu được phép quá tải ngắn hạn 75% trong bao lâu?",opts:["120 phút","80 phút","45 phút","20 phút"],ans:3,explain:"Quá tải 75% ngắn hạn chỉ cho phép 20 phút theo TT06."},
{id:8,q:"Theo TT06/2025/TT-BCT: Đường dây trên không vận hành đóng điện không tải hoặc dự phòng cần thực hiện theo phương án nào?",opts:["Không cần mở dao cách ly","Phải mở dao cách ly phía đường dây của các máy cắt đang mở.","Phải mở dao cách ly phía thanh cái của các máy cắt đang mở.","Phải mở dao cách ly cả 2 phía của các máy cắt đang mở."],ans:3,explain:"Phải mở dao cách ly cả 2 phía của máy cắt đang ở trạng thái mở."},
{id:9,q:"Theo TT06/2025/TT-BCT: Người duyệt phiếu thao tác theo kế hoạch trong phạm vi 01 trạm điện là?",opts:["Trưởng, Phó trạm điện hoặc người được ủy quyền.","Trưởng, Phó trạm điện hoặc Trưởng kíp, Trực chính.","Trưởng kíp, Trực chính.","Cả 3 phương án trên."],ans:0,explain:"Người duyệt phiếu thao tác kế hoạch trong 01 trạm là Trưởng, Phó trạm hoặc người được ủy quyền."},
{id:10,q:"Theo TT06/2025/TT-BCT, Cô lập bảo vệ so lệch thanh cái khi có điều kiện nào?",opts:["Bảo vệ so lệch thanh cái còn lại làm việc bình thường","Đặt bảo vệ dự phòng sự cố thanh cái","Cắt điện thanh cái này","Phương án A hoặc B hoặc C"],ans:3,explain:"Cho phép cô lập bảo vệ so lệch thanh cái khi thỏa mãn A hoặc B hoặc C."},
{id:11,q:"Theo TT06/2025/TT-BCT: Cho phép thao tác trong điều kiện thời tiết xấu theo phương án nào?",opts:["Thực hiện thao tác ngoài trời khi có mưa tạo thành dòng chảy trên thiết bị điện","Thực hiện thao tác ngoài trời có gió từ cấp 6 trở lên","Thực hiện các thao tác trong nhà và không cần thiết phải kiểm tra ngay trạng thái tại chỗ của thiết bị đóng cắt","Thực hiện thao tác ngoài trời khi sân trạm bị ngập lụt"],ans:2,explain:"Chỉ được phép thao tác trong nhà và không cần kiểm tra trạng thái tại chỗ ngay khi thời tiết xấu."},
{id:12,q:"Theo TT06/2025/TT-BCT, Tổ máy phát có tổng công suất đặt lớn hơn 30MW đấu nối lưới 220kV, 110kV thuộc quyền điều khiển của cấp điều độ nào trong trường hợp rã lưới:",opts:["Cấp điều độ quốc gia.","Cấp điều độ miền.","Cấp điều độ quốc gia điều khiển công suất tác dụng, Cấp điều độ miền điều khiển công suất phản kháng.","Không quy định"],ans:1,explain:"Trong trường hợp rã lưới, tổ máy đấu nối 220kV, 110kV thuộc quyền điều khiển của cấp điều độ miền."},
{id:13,q:"Theo TT06/2025/TT-BCT, quan hệ giữa lãnh đạo trực tiếp với nhân viên vận hành của mình:",opts:["NVVH cấp dưới phải thực hiện theo lệnh của lãnh đạo trực tiếp trong mọi tình huống","Khi lệnh lãnh đạo trực tiếp trái lệnh điều độ, NVVH thực hiện theo lệnh lãnh đạo trong trường hợp nguy hiểm đến tính mạng","Lệnh lãnh đạo trực tiếp không được trái với lệnh NVVH cấp trên và/hoặc quy chuẩn, quy trình, quy định hiện hành.","B và C đúng"],ans:3,explain:"Cả B và C đều đúng theo quy định TT06."},
{id:14,q:"Theo TT06/2025/TT-BCT, quy định về điều khiển tần số sơ cấp:",opts:["Được thực hiện tự động bởi số lượng lớn các tổ máy phát điện có trang bị hệ thống điều tốc","Được thực hiện thông qua tác động hệ thống AGC","Được thực hiện bằng lệnh điều độ","Cả 3 đáp án đều đúng"],ans:0,explain:"Điều khiển tần số sơ cấp được thực hiện tự động bởi các tổ máy có hệ thống điều tốc."},
{id:15,q:"Theo TT06/2025/TT-BCT, sai số dự báo phụ tải ngày, chu kỳ giao dịch trong giới hạn:",opts:["± 4%","± 6 %","± 8%","± 10%"],ans:0,explain:"Sai số dự báo phụ tải ngày, chu kỳ giao dịch trong giới hạn ± 4%."},
{id:16,q:"Theo TT06/2025/TT-BCT, lập phiếu thao tác là trách nhiệm của bộ phận nào tại cấp điều độ miền:",opts:["Bộ phận phương thức dài hạn","Bộ phận phương thức ngắn hạn","Bộ phận trực ban chỉ huy điều độ miền","Không quy định"],ans:2,explain:"Lập phiếu thao tác là trách nhiệm của bộ phận trực ban chỉ huy điều độ miền."},
{id:17,q:"Theo TT06/2025/TT-BCT: Thời gian phiếu thao tác đột xuất phải được chuyển tới nhân viên vận hành trực tiếp thao tác trước thời gian dự kiến bắt đầu thao tác?",opts:["60 phút","45 phút","30 phút","Không quy định"],ans:2,explain:"Phiếu thao tác đột xuất phải chuyển trước 30 phút so với thời gian dự kiến bắt đầu."},
{id:18,q:"Theo TT06/2025/TT-BCT: Ai có quyền cho phép thay đổi chế độ làm việc của mạch khóa liên động?",opts:["Lãnh đạo trực tiếp đơn vị.","Nhân viên vận hành cấp trên.","Nhân viên vận hành.","Lãnh đạo trực tiếp đơn vị hoặc nhân viên vận hành cấp trên."],ans:3,explain:"Lãnh đạo trực tiếp đơn vị hoặc nhân viên vận hành cấp trên có quyền cho phép thay đổi mạch khóa liên động."},
{id:19,q:"Theo TT06/2025/TT-BCT, Nhân viên vận hành phải xử lý theo phương án nào nếu thanh cái bị mất điện?",opts:["Kiểm tra thanh cái không có điện áp, cắt các máy cắt nối thanh cái nếu đang đóng","Cắt toàn bộ máy cắt nối thanh cái bị mất điện","Cắt toàn bộ dao cách ly nối thanh cái bị mất điện","Báo cáo lãnh đạo trực tiếp"],ans:0,explain:"Khi thanh cái mất điện phải kiểm tra không có điện áp, sau đó cắt các máy cắt nối thanh cái nếu đang đóng."},
{id:20,q:"Theo TT06/2025/TT-BCT: Trường hợp nào sau đây không cần lập phiếu thao tác:",opts:["Chỉ thực hiện 01 thao tác tại chỗ","Thực hiện 04 bước thao tác từ cấp điều độ có quyền điều khiển","Thực hiện 03 bước thao tác bằng điều khiển từ xa","Đáp án B và C"],ans:0,explain:"Chỉ thực hiện 01 thao tác tại chỗ thì không cần lập phiếu thao tác."},
{id:21,q:"Theo TT06/2025/TT-BCT: Ghi tên Người giám sát trong phiếu thao tác do cấp điều độ miền lập đúng theo phương án nào?",opts:["Ghi họ và tên Điều độ viên phụ trách","Ghi họ và tên Phó phòng Điều độ","Ghi họ và tên Trưởng phòng Điều độ","Ghi họ và tên Điều độ viên ra lệnh trực tiếp"],ans:3,explain:"Ghi họ và tên Điều độ viên ra lệnh trực tiếp là người giám sát."},
{id:22,q:"Theo TT06/2025/TT-BCT, Đường dây 220kV phải tách ra khỏi vận hành khi thiếu rơ le bảo vệ trong trường hợp nào?",opts:["Bảo vệ quá dòng thứ tự không có hướng","Bảo vệ khoảng cách","Bảo vệ còn lại không bảo đảm chống mọi dạng sự cố","Bảo vệ cắt nhanh"],ans:2,explain:"Phải tách đường dây khi bảo vệ còn lại không bảo đảm chống mọi dạng sự cố."},
{id:23,q:"Theo TT05/2025/TT-BCT, quy định về hệ số chạm đất của lưới điện truyền tải:",opts:["Không vượt quá 1.4","Không vượt quá 1.5","Không vượt quá 1.6","Không vượt quá 1.7"],ans:1,explain:"Hệ số chạm đất của lưới điện truyền tải không vượt quá 1.5 theo TT05."},
{id:24,q:"Theo TT06/2025/TT-BCT, khi sự cố đường dây cấp điện áp trên 35 kV đến 220 kV, cho phép đóng lại bao nhiêu lần?",opts:["Không được phép đóng lại","Không quá 01 lần, kể cả lần tự động đóng lại không thành công","Không quá 02 lần, kể cả lần tự động đóng lại không thành công","Không quá 03 lần, kể cả lần tự động đóng lại không thành công"],ans:1,explain:"Cho phép đóng lại không quá 01 lần, kể cả lần tự động đóng lại không thành công."},
{id:25,q:"Theo TT06/2025/TT-BCT: Phiếu thao tác đột xuất trong phạm vi 01 trạm điện do đơn vị quản lý vận hành viết, duyệt được quy định như sau:",opts:["Người viết: NVVH trạm; Người duyệt: Trưởng kíp, Trực chính.","Người viết: NVVH trạm; Người duyệt: Trưởng, Phó trạm điện.","Người viết: NVVH trạm; Người duyệt: Trưởng, Phó trạm hoặc Trưởng kíp, Trực chính.","Cả 3 phương án trên"],ans:2,explain:"Người duyệt phiếu đột xuất trong 01 trạm là Trưởng, Phó trạm điện hoặc Trưởng kíp, Trực chính."},
{id:26,q:"Theo TT05/2025/TT-BCT, Phương án nào hệ thống điện truyền tải vận hành ở chế độ cực kỳ khẩn cấp?",opts:["Dự phòng nguồn điện gần bằng không hợp ngăn ngừa sự cố phát triển rộng","Mức mang tải của máy biến áp 220 kV là 110%","Điện áp cao nhất trên lưới 500 kV là 545 kV","Tần số hệ thống 50,6 Hz"],ans:0,explain:"Dự phòng nguồn điện gần bằng 0 không đủ ngăn ngừa sự cố phát triển là dấu hiệu cực kỳ khẩn cấp."},
{id:27,q:"Theo TT06/2025/TT-BCT: Ý nào không đúng theo quy định yêu cầu máy cắt cần được đưa ra kiểm tra bảo dưỡng?",opts:["Cắt tổng dòng ngắn mạch đến mức quy định","Số lần cắt ngắn mạch đến mức quy định","Thời gian vận hành đến mức quy định","Quá 1 năm không thao tác đóng mở MC"],ans:3,explain:"Quá 1 năm không thao tác không phải là tiêu chí để đưa máy cắt ra bảo dưỡng theo quy định."},
{id:28,q:"Theo TT06/2025/TT-BCT, Mẫu Báo cáo sự cố của Đơn vị quản lý vận hành gửi cấp điều độ theo phương án nào?",opts:["Theo mẫu quy định tại Phụ lục VI ban hành kèm theo Thông tư trên","Theo mẫu quy định tại Phụ lục VII ban hành kèm theo Thông tư trên","Theo mẫu quy định tại Phụ lục VIII ban hành kèm theo Thông tư trên","Theo mẫu quy định tại Phụ lục IX ban hành kèm theo Thông tư trên"],ans:0,explain:"Báo cáo sự cố theo mẫu Phụ lục VI của TT06."},
{id:29,q:"Theo TT06/2025/TT-BCT: Thẩm quyền cho phép máy cắt được cắt sự cố thêm khi vượt quá số lần quy định?",opts:["Giám đốc hoặc phó giám đốc kỹ thuật đơn vị quản lý vận hành thiết bị.","Cấp điều độ có quyền điều khiển thiết bị.","Trưởng kíp trực vận hành thiết bị.","Cấp điều độ có quyền kiểm tra thiết bị."],ans:0,explain:"Giám đốc hoặc Phó giám đốc kỹ thuật đơn vị QLVH có thẩm quyền cho phép MC cắt sự cố thêm."},
{id:30,q:"Theo TT06/2025/TT-BCT, quy định về thời gian phê duyệt và công bố sơ đồ kết dây cơ bản của hệ thống điện:",opts:["Trước 20 tháng 08 hàng năm","Trước 20 tháng 09 hàng năm","Trước 20 tháng 10 hàng năm","Trước 20 tháng 11 hàng năm"],ans:2,explain:"Sơ đồ kết dây cơ bản phải phê duyệt và công bố trước ngày 20 tháng 10 hàng năm."},
{id:31,q:"Theo TT06/2025/TT-BCT: Trong trường hợp có chạm đất mạch điều khiển máy cắt:",opts:["Vẫn được phép thao tác máy cắt.","Chỉ cho phép thao tác máy cắt khi xử lý sự cố.","Chỉ cho phép thao tác máy cắt khi có sự cho phép của lãnh đạo trực tiếp.","Cả A, B, C đều sai."],ans:1,explain:"Khi chạm đất mạch điều khiển, chỉ cho phép thao tác máy cắt khi xử lý sự cố."},
{id:32,q:"Theo TT06/2025/TT-BCT, Nội dung đăng ký phương thức vận hành:",opts:["Dự báo phụ tải hệ thống điện thuộc quyền điều khiển","Dự kiến kế hoạch bảo dưỡng, sửa chữa lưới điện thuộc quyền kiểm tra của điều độ cấp trên","Dự kiến kế hoạch vào vận hành của các công trình điện mới thuộc quyền kiểm tra của điều độ cấp trên","Cả 3 đáp án trên đều đúng"],ans:3,explain:"Nội dung đăng ký phương thức vận hành bao gồm cả 3 nội dung A, B, C."},
{id:33,q:"Theo TT06/2025/TT-BCT, Chế độ vận hành thiếu trang bị rơ le bảo vệ hoặc tự động phải được quy định cụ thể bởi?",opts:["Cấp điều độ có quyền điều khiển.","Cục Điều tiết điện lực.","Đơn vị quản lý vận hành.","Tập đoàn Điện lực Việt Nam"],ans:0,explain:"Cấp điều độ có quyền điều khiển quy định chế độ vận hành thiếu rơ le bảo vệ."},
{id:34,q:"Theo TT06/2025/TT-BCT: Đơn vị QLVH thực hiện thao tác thử đóng cắt MC, dao cách ly bằng điều khiển từ xa nếu thời gian không thao tác kéo dài quá?",opts:["03 tháng và không gây gián đoạn cung cấp điện cho khách hàng","06 tháng và không gây gián đoạn cung cấp điện cho khách hàng","12 tháng và không gây gián đoạn cung cấp điện cho khách hàng","Không quy định"],ans:0,explain:"Thao tác thử khi không thao tác quá 03 tháng và không gây gián đoạn cung cấp điện."},
{id:35,q:"Theo TT06/2025/TT-BCT: Cho phép ủy quyền điều khiển theo phương án nào:",opts:["Thay đổi chế độ vận hành của thiết bị điện không ảnh hưởng đến chế độ vận hành của hệ thống điện thuộc quyền điều khiển","Cấp điều độ có quyền điều khiển ủy quyền cho điều độ cấp dưới hoặc Đơn vị QLVH","Văn bản có sự xác nhận của hai bên về việc ủy quyền","Phương án A, B, C"],ans:3,explain:"Ủy quyền điều khiển phải thỏa mãn cả 3 điều kiện A, B, C."},
{id:36,q:"Theo TT06/2025/TT-BCT, ai là người cho phép thay đổi trị số chỉnh định rơ le bảo vệ và tự động hóa:",opts:["Trưởng kíp trạm điện","Điều độ viên cấp điều độ có quyền điều khiển","Kỹ sư phương thức được giao nhiệm vụ lập phiếu chỉnh định rơ le bảo vệ","Lãnh đạo đơn vị quản lý vận hành"],ans:1,explain:"Điều độ viên cấp điều độ có quyền điều khiển là người cho phép thay đổi trị số chỉnh định rơ le."},
{id:37,q:"Theo TT06/2025/TT-BCT: Điều kiện thời tiết nào không được thực hiện thao tác ngoài trời tại vị trí đặt thiết bị điện?",opts:["Trời có mưa","Sân trạm bị ngập","Có gió mạnh","Trời nắng gắt"],ans:1,explain:"Không được thực hiện thao tác ngoài trời khi sân trạm bị ngập lụt."},
{id:38,q:"Theo TT06/2025/TT-BCT: Trước khi đóng dao tiếp địa đường dây phải thực hiện theo phương án nào?",opts:["Kiểm tra đường dây không còn điện áp, trạng thái tại chỗ máy cắt, dao cách ly hai đầu đường dây đã mở tốt 3 pha","Kiểm tra điện áp đường dây qua TU đường dây gần bằng 0 kV","Kiểm tra trạng thái tại chỗ máy cắt, dao cách ly đường dây đã mở tốt 3 pha","Phương án B, C"],ans:0,explain:"Phải kiểm tra đường dây không còn điện áp VÀ trạng thái máy cắt, dao cách ly hai đầu đã mở tốt 3 pha trước khi đóng dao tiếp địa."},
{id:39,q:"Theo TT06/2025/TT-BCT, thời gian quy định có mặt trước giờ giao nhận ca đối với nhân viên vận hành:",opts:["ít nhất 15 phút","ít nhất 10 phút","ít nhất 5 phút","có mặt đúng giờ"],ans:0,explain:"NVVH phải có mặt ít nhất 15 phút trước giờ giao nhận ca."},
{id:40,q:"Theo TT06/2025/TT-BCT: Quy định khi phải cắt dao tiếp địa cố định mà vẫn có đội công tác trên đường dây?",opts:["Phải đặt tiếp địa di động thay thế trước khi cắt các dao tiếp địa","Phải đóng tiếp địa khác hoặc đặt tiếp địa di động thay thế trước khi cắt các dao tiếp địa","Phải đóng tiếp địa khác hoặc đặt tiếp địa di động thay thế sau khi đã cắt các dao tiếp địa","Phải đặt tiếp địa di động thay thế sau khi đã cắt các dao tiếp địa"],ans:1,explain:"Phải đóng tiếp địa khác hoặc đặt tiếp địa di động thay thế TRƯỚC KHI cắt dao tiếp địa cố định."},
{id:41,q:"Theo TT06/2025/TT-BCT, quy định về giới hạn điện áp:",opts:["Giá trị điện áp lớn nhất cho phép thiết bị vận hành lâu dài theo quy định của nhà chế tạo","Giá trị điện áp nhỏ nhất cho phép thiết bị vận hành lâu dài theo quy định của nhà chế tạo","Cả 2 câu A và B đều đúng","Cả 2 câu A và B đều sai"],ans:2,explain:"Giới hạn điện áp bao gồm cả giá trị lớn nhất và nhỏ nhất cho phép vận hành lâu dài."},
{id:42,q:"Theo TT06/2025/TT-BCT: Đơn vị nào có trách nhiệm lập phương án khởi động đen và khôi phục hệ thống điện quốc gia có cấp điện áp từ 220kV trở lên:",opts:["Cấp điều độ quốc gia","Cấp điều độ miền","EVN","Cục Điều tiết điện lực"],ans:0,explain:"Cấp điều độ quốc gia lập phương án khởi động đen cho hệ thống điện từ 220kV trở lên."},
{id:43,q:"Theo TT06/2025/TT-BCT, máy biến áp dầu được phép quá tải ngắn hạn 30% trong bao lâu?",opts:["120 phút","80 phút","45 phút","20 phút"],ans:0,explain:"Quá tải ngắn hạn 30% cho phép 120 phút."},
{id:44,q:"Theo TT06/2025/TT-BCT: Đơn vị đề nghị thao tác trong phiếu thao tác tách đường dây do cấp điều độ quốc gia lập phiếu thao tác ghi đúng theo phương án nào?",opts:["Ghi tên cấp điều độ có quyền điều khiển đề nghị thao tác","Ghi tên các đơn vị quản lý vận hành đăng ký công tác","Ghi tên đơn vị công tác và cả đơn vị kết hợp công tác trên đường dây, thiết bị điện","Ghi tên trạm điện, nhà máy điện đề nghị thao tác"],ans:1,explain:"Ghi tên các đơn vị quản lý vận hành đăng ký công tác trong phiếu thao tác."},
{id:45,q:"Theo TT06/2025/TT-BCT, Trường hợp nào sau đây không được phép đóng lại:",opts:["Sự cố đường cáp cấp 110kV","Sự cố đường dây hỗn hợp cấp 220kV và tín hiệu rơle báo sự cố nằm ngoài phạm vi đường cáp","Sự cố đường dây hỗn hợp cấp 110kV và đường cáp chỉ là đoạn ngắn của đường dây trên không","Cả 3 đáp án trên"],ans:0,explain:"Không được phép đóng lại khi sự cố đường cáp cấp 110kV."},
{id:46,q:"Theo TT06/2025/TT-BCT, Phương án nào không cho phép khôi phục ngay đường dây 220kV sau sự cố?",opts:["Đang có công tác sửa chữa nóng trên đường dây","Đường dây sự cố 1 pha và tự động đóng lại không thành công","Đường dây sự cố 2 pha và tự động đóng lại không thành công","Đường dây sự cố 3 pha và tự động đóng lại không thành công"],ans:3,explain:"Đường dây sự cố 3 pha và tự động đóng lại không thành công thì không cho phép khôi phục ngay."},
{id:47,q:"Theo TT06/2025/TT-BCT: Quy định ghi số phiếu thao tác theo kế hoạch trong tháng tại cấp điều độ miền đúng theo phương án nào?",opts:["Số TT phiếu KH trong năm / năm phát hành / KH / tên viết tắt cấp điều độ miền","Số TT phiếu KH trong tháng / tháng phát hành / KH / tên viết tắt cấp điều độ miền","KH / số TT phiếu KH trong năm / năm phát hành / tên viết tắt trung tâm điều độ miền","Tên viết tắt cấp điều độ miền / KH / số TT phiếu KH trong năm / năm phát hành"],ans:3,explain:"Ghi theo thứ tự: Tên viết tắt cấp điều độ miền / KH / số TT / năm phát hành."},
{id:48,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng người ra lệnh không phải thông báo rõ họ tên mình:",opts:["Thao tác thay đổi công suất tổ máy để điều chỉnh tần số","Thao tác thay đổi nấc máy biến áp để điều chỉnh điện áp","Thao tác xa","Không quy định"],ans:0,explain:"Khi thao tác thay đổi công suất tổ máy để điều chỉnh tần số, người ra lệnh không phải thông báo rõ họ tên."},
{id:49,q:"Theo TT06/2025/TT-BCT: Quy định đối với thao tác xa có kế hoạch liên quan đến giao nhận thiết bị?",opts:["ĐVQLVH phải cử NVVH tới trực tại trạm điện hoặc nhà máy điện trong thời gian thực hiện thao tác xa","ĐVQLVH phải cử NVVH tới trực tại trạm điện hoặc nhà máy điện trong thời gian thực hiện thao tác xa để thực hiện biện pháp an toàn và giao nhận thiết bị","Thao tác tại các Cấp điều độ, Trung tâm điều khiển và giao nhận thiết bị với trực ban của ĐVQLVH","Thao tác tại các Cấp điều độ và giao nhận thiết bị với trực ban của ĐVQLVH"],ans:1,explain:"ĐVQLVH phải cử NVVH tới trực để thực hiện biện pháp an toàn và giao nhận thiết bị khi thao tác xa có kế hoạch."},
{id:50,q:"Theo TT06/2025/TT-BCT, nguyên tắc lập sơ đồ kết dây cơ bản trong hệ thống điện:",opts:["Bảo đảm tính chọn lọc của rơ le bảo vệ","Linh hoạt, thuận tiện trong thao tác xử lý sự cố","Bảo đảm dòng ngắn mạch không vượt quá giá trị cho phép đối với thiết bị","Cả 3 đáp án trên đều đúng"],ans:3,explain:"Sơ đồ kết dây cơ bản phải đảm bảo đồng thời cả 3 nguyên tắc A, B, C."},
{id:51,q:"Theo TT06/2025/TT-BCT, các mức dự báo phụ tải điện:",opts:["Năm, tháng, tuần, ngày","Tháng, tuần, ngày","Tuần, ngày, chu kỳ giao dịch","Năm, tháng, tuần, ngày, chu kỳ giao dịch"],ans:3,explain:"Các mức dự báo phụ tải gồm: Năm, tháng, tuần, ngày, chu kỳ giao dịch."},
{id:52,q:"Theo TT06/2025/TT-BCT: Người ra lệnh bao gồm những đối tượng nào?",opts:["Điều độ viên tại các cấp điều độ; Trưởng ca NMĐ; Trưởng kíp TĐ; Trưởng ca NMĐ hoặc Trưởng kíp TĐ của trung tâm điều khiển; Nhân viên trực thao tác lưu động","Điều độ viên tại các cấp điều độ","Điều độ viên tại các cấp điều độ; Trưởng ca nhà máy điện; Trưởng kíp trạm điện","Nhân viên vận hành được giao nhiệm vụ tại các cấp điều độ, trạm điện, nhà máy điện hoặc trung tâm điều khiển."],ans:0,explain:"Người ra lệnh gồm tất cả các đối tượng nêu tại phương án A."},
{id:53,q:"Theo TT06/2025/TT-BCT, sai số dự báo phụ tải năm, tháng, tuần:",opts:["± 6%","± 8 %","± 10%","± 15%"],ans:0,explain:"Sai số dự báo phụ tải năm, tháng, tuần trong giới hạn ± 6%."},
{id:54,q:"Theo TT06/2025/TT-BCT: Trước khi đưa thiết bị hoặc đường dây vào vận hành sau sửa chữa thì nhân viên vận hành cần lưu ý điều kiện gì?",opts:["ĐVQLVH phải khẳng định người và phương tiện đã rút hết.","ĐVQLVH phải khẳng định các tiếp địa di động đã tháo hết.","ĐVQLVH phải khẳng định chắc chắn các đơn vị công tác (người và phương tiện) đã rút hết, đã tháo hết tiếp địa di động, đã khoá tất cả các phiếu công tác; đường dây, thiết bị đủ tiêu chuẩn vận hành và sẵn sàng nhận điện.","Đơn vị thi công phải khẳng định người và phương tiện đã rút hết"],ans:2,explain:"ĐVQLVH phải khẳng định đầy đủ: người và phương tiện rút hết, tiếp địa di động tháo hết, đã khóa phiếu công tác, thiết bị đủ tiêu chuẩn và sẵn sàng nhận điện."},
{id:55,q:"Theo TT05/2025/TT-BCT, đơn vị nào có trách nhiệm ban hành phiếu chỉnh định rơ le thuộc phạm vi lưới điện truyền tải của đơn vị truyền tải điện:",opts:["Đơn vị truyền tải điện","Đơn vị điều độ hệ thống điện","Cấp điều độ có quyền điều khiển","Không có đáp án đúng"],ans:1,explain:"Đơn vị điều độ hệ thống điện có trách nhiệm ban hành phiếu chỉnh định rơ le thuộc lưới điện truyền tải."},
{id:56,q:"Theo TT06/2025/TT-BCT: Thao tác đóng điện thiết bị bù mới khác với thiết bị bù sau sửa chữa ở điểm nào?",opts:["Dùng máy cắt và rơ le bảo vệ (nếu có) đã được chỉnh định để đóng điện thiết bị bù","Điện áp phải được điều chỉnh phù hợp, đảm bảo không bị dao động điện áp quá giới hạn khi đóng điện","Thiết bị bù được thí nghiệm đủ tiêu chuẩn vận hành","Trình tự thao tác tương tự như nhau"],ans:0,explain:"Thiết bị bù mới phải dùng máy cắt và rơ le bảo vệ đã được chỉnh định để đóng điện lần đầu."},
{id:57,q:"Theo TT06/2025/TT-BCT, định nghĩa về hệ thống điện miền:",opts:["là hệ thống điện có cấp điện áp đến 220kV và ranh giới phân chia theo miền Bắc, Trung, Nam","là hệ thống điện có cấp điện áp đến 500kV và ranh giới phân chia theo miền Bắc, Trung, Nam","là hệ thống điện có cấp điện áp đến 110kV và ranh giới phân chia theo miền Bắc, Trung, Nam","Cả 3 câu trên đều đúng"],ans:0,explain:"Hệ thống điện miền là hệ thống điện có cấp điện áp đến 220kV, chia theo miền Bắc, Trung, Nam."},
{id:58,q:"Theo TT06/2025/TT-BCT: Trong các trường hợp sau, trường hợp nào tạm ngừng thao tác là không đúng?",opts:["Thời gian thao tác kéo dài liên tục quá 04 giờ đối với người thao tác trực tiếp tại trạm điện hoặc nhà máy điện.","Khi thao tác vào giờ cao điểm của hệ thống.","Thao tác phải thực hiện ngoài trời trong điều kiện thời tiết xấu;","Tạm ngừng thao tác cho tới khi xử lý xong sự cố, hiện tượng bất thường."],ans:1,explain:"Khi thao tác vào giờ cao điểm không phải là lý do tạm ngừng thao tác theo quy định."},
{id:59,q:"Theo TT06/2025/TT-BCT, thời gian lưu trữ lệnh điều độ điện tử:",opts:["ít nhất 2 năm","ít nhất 3 năm","ít nhất 4 năm","ít nhất 5 năm"],ans:3,explain:"Lệnh điều độ điện tử phải lưu trữ ít nhất 5 năm."},
{id:60,q:"Theo TT05/2025/TT-BCT, quy định về dao động điện áp:",opts:["là sự biến đổi biên độ điện áp so với điện áp danh định trong thời gian dài hơn 04 phút","là sự biến đổi biên độ điện áp so với điện áp danh định trong thời gian dài hơn 03 phút","là sự biến đổi biên độ điện áp so với điện áp danh định trong thời gian dài hơn 02 phút","là sự biến đổi biên độ điện áp so với điện áp danh định trong thời gian dài hơn 01 phút"],ans:3,explain:"Dao động điện áp là sự biến đổi biên độ điện áp trong thời gian dài hơn 01 phút."},
{id:61,q:"Theo TT06/2025/TT-BCT: Thời gian không thao tác kéo dài quá bao nhiêu tháng thì ĐVQLVH phải thực hiện thao tác thử đóng cắt máy cắt, dao cách ly bằng điều khiển từ xa?",opts:["12 tháng","24 tháng","3 tháng","6 tháng"],ans:3,explain:"Không thao tác quá 6 tháng thì phải thao tác thử bằng điều khiển từ xa (không gây gián đoạn cấp điện)."},
{id:62,q:"Theo TT05/2025/TT-BCT, cấu hình của hệ thống đo đếm không bao gồm:",opts:["Công tơ đo đếm","CT","VT","Máy cắt đường dây"],ans:3,explain:"Máy cắt đường dây không phải là thành phần trong cấu hình hệ thống đo đếm điện năng."},
{id:63,q:"Theo TT06/2025/TT-BCT: Trong trường hợp chạm đất mạch điều khiển của máy cắt:",opts:["Vẫn cho phép thao tác máy cắt.","Cắt aptomat cấp nguồn điều khiển máy cắt.","Không cho phép thao tác máy cắt.","Cho phép thao tác máy cắt trong chế độ sự cố."],ans:2,explain:"Khi chạm đất mạch điều khiển máy cắt, không cho phép thao tác máy cắt."},
{id:64,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định đúng trình tự xử lý đầu tiên của Trưởng kíp trạm điện khi quá tải máy biến áp?",opts:["Xử lý quá tải máy biến áp theo quy trình","Hoàn thành Báo cáo nhanh theo quy định","Báo cáo ngay cho Cấp điều độ có quyền điều khiển","Chuyển tự dùng xoay chiều sang nhận từ nguồn dự phòng khác nếu mất tự dùng xoay chiều do sự cố máy biến áp"],ans:2,explain:"Trình tự đầu tiên khi quá tải MBA là báo cáo ngay cho Cấp điều độ có quyền điều khiển."},
{id:65,q:"Theo TT06/2025/TT-BCT, Nhân viên vận hành phải lấy mẫu khí trong rơ le để phân tích và kiểm tra tính chất cháy của khí trong trường hợp nào:",opts:["Khi silicagen đổi màu.","Khi rơle hơi tác động báo tín hiệu","Khi máy biến áp bị nhảy sự cố do bảo vệ quá dòng tác động","Khi máy biến áp bị nhảy sự cố do bảo vệ so lệch tác động"],ans:1,explain:"Khi rơle hơi tác động báo tín hiệu thì phải lấy mẫu khí để phân tích và kiểm tra tính chất cháy."},
{id:66,q:"Theo TT06/2025/TT-BCT: Phương án nào đúng cho phép nhân viên vận hành không cần lập phiếu thao tác?",opts:["Thao tác đột xuất trong phạm vi 01 trạm điện, một nhà máy điện, trung tâm điều khiển","Thao tác đột xuất trong phạm vi 01 trạm điện, một nhà máy điện, trung tâm điều khiển hoặc tại các cấp điều độ bằng điều khiển từ xa","Thao tác có số bước không quá 03 bước và được thực hiện tại trung tâm điều khiển hoặc thao tác bằng điều khiển từ xa","Thao tác đơn giản có số bước không quá 05 bước và được thực hiện bằng điều khiển từ xa"],ans:2,explain:"Thao tác có số bước không quá 03 bước thực hiện tại trung tâm điều khiển hoặc điều khiển từ xa thì không cần lập phiếu thao tác."},
{id:67,q:"Theo TT06/2025/TT-BCT, trường hợp nào cấp điều độ có quyền điều khiển được phép ra lệnh điều độ trước:",opts:["Xử lý sự cố hoặc đe dọa sự cố","Trường hợp không liên lạc được với cấp điều độ có quyền kiểm tra","có thể ra lệnh điều độ trước báo cáo cấp điều độ có quyền kiểm tra sau trong mọi trường hợp","Phải báo cáo cấp điều độ có quyền kiểm tra trước khi ra lệnh điều độ trong tất cả trường hợp"],ans:0,explain:"Được phép ra lệnh điều độ trước khi báo cáo cấp điều độ có quyền kiểm tra chỉ khi xử lý sự cố hoặc đe dọa sự cố."},
{id:68,q:"Theo TT06/2025/TT-BCT: Nhân viên vận hành không được tự ý tách hoặc cô lập các mạch khoá liên động. Trường hợp cần thay đổi mạch khoá liên động phải được sự đồng ý của?",opts:["Của lãnh đạo trực tiếp đơn vị","Của nhân viên vận hành cấp trên","Của nhân viên trực ban vận hành","A hoặc B"],ans:3,explain:"Cần được sự đồng ý của lãnh đạo trực tiếp đơn vị hoặc nhân viên vận hành cấp trên."},
{id:69,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng cho phép cấp điều độ quốc gia tạm ngừng thao tác?",opts:["Thời gian thao tác kéo dài liên tục quá 04 giờ","Thao tác thực hiện trong điều kiện thời tiết xấu","Đang thao tác thì xảy ra sự cố hoặc có cảnh báo hiện tượng bất thường","Không quy định"],ans:2,explain:"Tạm ngừng thao tác khi đang thao tác thì xảy ra sự cố hoặc có cảnh báo hiện tượng bất thường."},
{id:70,q:"Theo TT06/2025/TT-BCT, Chi phí duy trì hệ thống khởi động đen sẵn sàng được xác định theo nguyên tắc nào:",opts:["Đối với NMĐ có tổng công suất đặt lớn hơn 30 MW, có ý nghĩa đặc biệt quan trọng: Là một phần trong tổng chi phí hàng năm do EVN xây dựng, trình Bộ Công Thương phê duyệt","Đối với NMĐ đã cung cấp dịch vụ dự phòng khởi động nhanh: Được tính trong giá dịch vụ phụ trợ hàng năm của nhà máy điện","Đối với NMĐ đã có giá hợp đồng mua bán điện: Đơn vị phát điện tính toán chi phí hàng năm phục vụ duy trì, bảo dưỡng sẵn sàng hệ thống thiết bị khởi động đen","Đáp án A, B, C"],ans:3,explain:"Chi phí duy trì hệ thống khởi động đen xác định theo cả 3 nguyên tắc A, B, C."},
{id:71,q:"Theo TT06/2025/TT-BCT, Trách nhiệm khắc phục khiếm khuyết của trang thiết bị rơ le bảo vệ và tự động trong trường hợp tác động sai hoặc từ chối tác động?",opts:["Đơn vị quản lý vận hành","Cấp điều độ có quyền điều khiển","Nhân viên vận hành","Phương án A, B"],ans:0,explain:"Đơn vị quản lý vận hành chịu trách nhiệm khắc phục khiếm khuyết của trang thiết bị rơ le bảo vệ."},
{id:72,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng trách nhiệm viết và duyệt phiếu thao tác đóng điện nghiệm thu máy biến áp mới tại trạm điện hoặc nhà máy điện?",opts:["Hội đồng nghiệm thu","Đơn vị quản lý vận hành","Cấp điều độ có quyền điều khiển","Không quy định"],ans:1,explain:"Đơn vị quản lý vận hành có trách nhiệm viết và duyệt phiếu thao tác đóng điện nghiệm thu MBA mới."},
{id:73,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định đúng quan hệ công tác trong xử lý sự cố?",opts:["Nhân viên vận hành cấp trên có quyền thay thế nhân viên vận hành cấp dưới","Nhân viên vận hành cấp dưới có quyền không chấp hành mệnh lệnh của Nhân viên vận hành cấp trên","Nhân viên vận hành cấp dưới phải thi hành lệnh của Lãnh đạo trực tiếp","Nhân viên vận hành phải kịp thời báo cáo sự cố nghiêm trọng cho Lãnh đạo trực tiếp"],ans:3,explain:"Trong xử lý sự cố, nhân viên vận hành phải kịp thời báo cáo sự cố nghiêm trọng cho Lãnh đạo trực tiếp."},
{id:74,q:"Theo TT05/2025/TT-BCT, hệ thống điện vận hành ở chế độ cảnh báo khi xuất hiện hiện tượng nào:",opts:["Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp từ 90% trở lên nhưng không vượt quá giá trị định mức","Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp trên 90% nhưng không vượt quá giá trị định mức","Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp từ 80 % trở lên nhưng không vượt quá giá trị định mức","Cả A,B,C đều sai"],ans:0,explain:"Chế độ cảnh báo khi mức mang tải từ 90% trở lên nhưng không vượt quá giá trị định mức."},
{id:75,q:"Theo TT06/2025/TT-BCT, Nhà máy điện khởi động đen dự phòng phải đáp ứng tiêu chí nào sau đây:",opts:["Có thời gian khởi động đen không quá 5 phút","Có thời gian khởi động đen không quá 10 phút","Có thời gian khởi động đen không quá 15 phút","Có thời gian khởi động đen không quá 20 phút"],ans:3,explain:"Nhà máy điện khởi động đen dự phòng phải có thời gian khởi động đen không quá 20 phút."},
{id:76,q:"Theo TT06/2025/TT-BCT, Cấp Điều độ có quyền điều khiển phải gửi Báo cáo sự cố cho cấp Điều độ có quyền kiểm tra:",opts:["Ngay sau khi sự cố xảy ra","Trong vòng 24 tiếng kể từ khi sự cố xảy ra","Trong vòng 48 tiếng kể từ khi sự cố xảy ra","Không phương án nào đúng"],ans:1,explain:"Cấp điều độ có quyền điều khiển phải gửi báo cáo sự cố trong vòng 24 giờ."},
{id:77,q:"Theo TT06/2025/TT-BCT, Nhân viên vận hành phải được đào tạo, kiểm tra diễn tập xử lý sự cố?",opts:["Ít nhất mỗi năm một lần","Ít nhất hai năm một lần","Ít nhất mỗi năm hai lần","Không quy định"],ans:0,explain:"NVVH phải được đào tạo, kiểm tra diễn tập xử lý sự cố ít nhất mỗi năm một lần."},
{id:78,q:"Theo TT05/2025/TT-BCT, Hệ thống điện vận hành ở chế độ cực kỳ khẩn cấp khi:",opts:["Điện áp tại một nút bất kỳ trên lưới điện truyền tải nằm ngoài dải điện áp cho phép đối với trường hợp xảy ra sự cố một phần tử","Mức mang tải của bất kỳ thiết bị nào trong lưới điện 110kV hoặc thiết bị đấu nối với lưới điện 110kV trên 110% giá trị định mức","Tần số hệ thống nằm ngoài dải tần số cho phép đối với trường hợp xảy ra sự cố một phần tử","Đáp án B và C"],ans:3,explain:"Chế độ cực kỳ khẩn cấp khi thỏa mãn điều kiện B và C."},
{id:79,q:"Theo TT06/2025/TT-BCT, Khi sự cố đường dây 110kV hoặc 220kV qua khu dân cư, tự động đóng lại không thành công, cho phép đóng lại bao nhiêu lần?",opts:["Đóng lại một lần","Không đóng lại ngay, chỉ đóng lại khi có yêu cầu từ Đơn vị quản lý vận hành","Xin ý kiến lãnh đạo để đóng lại một lần","Không đóng lại, cô lập đường dây bàn giao Đơn vị quản lý vận hành sửa chữa"],ans:3,explain:"Đường dây qua khu dân cư khi tự động đóng lại không thành công thì không đóng lại, cô lập bàn giao ĐVQLVH sửa chữa."},
{id:80,q:"Theo TT06/2025/TT-BCT: Phiếu thao tác đột xuất phối hợp nhiều trạm điện hoặc thao tác xa từ cấp điều độ do cấp điều độ có quyền điều khiển viết, duyệt được quy định như sau?",opts:["Người viết: Điều độ viên; Người duyệt: Trưởng, Phó phòng điều độ; Điều độ viên phụ trách ca trực","Người viết: Điều độ viên; Người duyệt: Trưởng, Phó đơn vị điều độ; Điều độ viên phụ trách ca trực","Người viết: Điều độ viên; Người duyệt: Trưởng, Phó đơn vị điều độ; Trưởng, Phó phòng điều độ; Điều độ viên phụ trách ca trực","Người viết: Điều độ viên; Người duyệt: Điều độ viên phụ trách ca trực"],ans:2,explain:"Người duyệt gồm: Trưởng, Phó đơn vị điều độ; Trưởng, Phó phòng điều độ; Điều độ viên phụ trách ca trực."},
{id:81,q:"Theo TT06/2025/TT-BCT, thời gian lưu trữ lệnh điều độ bằng lời nói:",opts:["ít nhất 1 năm","ít nhất 6 tháng","ít nhất 3 tháng","không cần lưu trữ"],ans:0,explain:"Lệnh điều độ bằng lời nói phải lưu trữ ít nhất 1 năm."},
{id:82,q:"Theo TT06/2025/TT-BCT, Trường hợp máy biến áp bị cắt sự cố do bảo vệ quá từ thông tác động, điều kiện để đưa máy biến áp trở lại vận hành:",opts:["ĐVQLVH khẳng định máy biến áp đủ tiêu chuẩn vận hành.","NVVH kiểm tra, báo cáo tình trạng bên ngoài MBA không phát hiện có dấu hiệu bất thường, khẳng định mạch bảo vệ không tác động nhầm.","ĐVQLVH đã tiến hành thí nghiệm, kiểm tra thử nghiệm các thông số, phân tích mẫu khí, mẫu dầu, khắc phục những nhược điểm bất thường đã phát hiện.","NVVH kiểm tra, báo cáo tình trạng bên ngoài của máy biến áp không phát hiện có dấu hiệu bất thường."],ans:2,explain:"Khi MBA bị cắt do bảo vệ quá từ thông, cần thí nghiệm, kiểm tra thông số, phân tích mẫu khí, mẫu dầu, khắc phục bất thường trước khi đưa vào vận hành."},
{id:83,q:"Theo TT05/2025/TT-BCT, Phương án nào hệ thống điện vận hành ở chế độ khẩn cấp?",opts:["Tần số hệ thống 49,5 Hz","Máy biến áp chính 220 kV đang mang tải là 100%","Điện áp thấp nhất trên lưới 220 kV là 195 kV","Phương án A, C"],ans:3,explain:"Chế độ khẩn cấp khi tần số 49,5 Hz VÀ/HOẶC điện áp 220kV thấp nhất là 195 kV (phương án A, C)."},
{id:84,q:"Theo TT06/2025/TT-BCT, Nhà máy điện khởi động đen dự phòng phải đáp ứng tiêu chí nào sau đây về cấp điện áp đấu nối:",opts:["Đấu nối trực tiếp cấp điện áp 500kV","Đấu nối trực tiếp cấp điện áp 220kV","Đấu nối trực tiếp cấp điện áp 110kV","Cả 3 đáp án trên"],ans:2,explain:"Nhà máy điện khởi động đen dự phòng phải đấu nối trực tiếp cấp điện áp 110kV."},
{id:85,q:"Theo TT05/2025/TT-BCT, quy định về dịch vụ phụ trợ trong hệ thống điện gồm:",opts:["Khởi động nhanh","Khởi động đen","Dự phòng vận hành phải phát","Cả A,B,C đều đúng"],ans:3,explain:"Dịch vụ phụ trợ gồm cả A (khởi động nhanh), B (khởi động đen) và C (dự phòng vận hành phải phát)."},
{id:86,q:"Theo TT06/2025/TT-BCT: Hành động đầu tiên khi Trưởng kíp trạm điện nhận thấy thanh cái bị sự cố là gì?",opts:["Kiểm tra và xác nhận trạng thái thiết bị, sau đó báo cáo cấp điều độ có quyền điều khiển","Cắt ngay toàn bộ dao cách ly trên thanh cái","Báo ngay cho lãnh đạo trực tiếp xin ý kiến","Đóng ngay thanh cái dự phòng"],ans:0,explain:"Hành động đầu tiên là kiểm tra, xác nhận trạng thái thiết bị rồi báo cáo cấp điều độ có quyền điều khiển."},
{id:87,q:"Theo TT06/2025/TT-BCT, Nhân viên vận hành bao gồm những đối tượng nào?",opts:["Điều độ viên tại các cấp điều độ","Trưởng ca nhà máy điện và Trưởng kíp trạm điện","Nhân viên trực thao tác lưu động và Trưởng ca, Trưởng kíp trung tâm điều khiển","Tất cả các đối tượng trên"],ans:3,explain:"Nhân viên vận hành gồm tất cả: Điều độ viên, Trưởng ca NMĐ, Trưởng kíp TĐ, NVVH trực thao tác lưu động và Trưởng ca/kíp trung tâm điều khiển."},
{id:88,q:"Theo TT06/2025/TT-BCT: Khi nào được phép đóng lại đường dây 220kV bị sự cố 2 pha mà tự động đóng lại không thành công?",opts:["Khi không có công tác sửa chữa nóng và không có bão từ cấp 6 trở lên","Chỉ đóng lại khi có lệnh của cấp điều độ quốc gia","Không cho phép đóng lại","Khi có lệnh của lãnh đạo đơn vị"],ans:0,explain:"Đường dây sự cố 2 pha, TĐLL không thành công vẫn được đóng lại nếu không có sửa chữa nóng và không có bão từ cấp 6 trở lên."},
{id:89,q:"Theo TT05/2025/TT-BCT, điện áp vận hành cho phép trên lưới 110kV ở chế độ bình thường:",opts:["± 5%","± 10%","+ 10% và - 5%","+ 5% và - 10%"],ans:1,explain:"Độ lệch điện áp vận hành cho phép trên lưới 110kV ở chế độ bình thường là ± 10%."},
{id:90,q:"Theo TT06/2025/TT-BCT, quy định về điều kiện hòa đồng bộ ở cấp điện áp 220kV:",opts:["Góc lệch pha không quá 15 độ, chênh lệch tần số không quá 0,10 Hz, chênh lệch điện áp không quá 5%","Góc lệch pha không quá 20 độ, chênh lệch tần số không quá 0,10 Hz, chênh lệch điện áp không quá 10%","Góc lệch pha không quá 25 độ, chênh lệch tần số không quá 0,15 Hz, chênh lệch điện áp không quá 10%","Góc lệch pha không quá 30 độ, chênh lệch tần số không quá 0,25 Hz, chênh lệch điện áp không quá 10%"],ans:3,explain:"Điều kiện hòa đồng bộ 220kV: góc lệch pha ≤ 30 độ, chênh lệch tần số ≤ 0,25 Hz, chênh lệch điện áp ≤ 10%."},
{id:91,q:"Theo TT06/2025/TT-BCT: Đơn vị nào có trách nhiệm kiểm tra và cấp Chứng nhận vận hành cho Điều độ viên quốc gia?",opts:["Cục Điều tiết điện lực","Tập đoàn Điện lực Việt Nam","Cấp điều độ quốc gia","Bộ Công Thương"],ans:3,explain:"Bộ Công Thương có trách nhiệm tổ chức kiểm tra và cấp Chứng nhận vận hành cho Điều độ viên quốc gia."},
{id:92,q:"Theo TT06/2025/TT-BCT: Phương án nào đúng về trách nhiệm của bộ phận phương thức ngắn hạn cấp điều độ miền?",opts:["Lập phương thức vận hành hàng tuần, hàng ngày","Lập phiếu thao tác","Trực ban chỉ huy điều độ","Lập kế hoạch đào tạo"],ans:0,explain:"Bộ phận phương thức ngắn hạn có trách nhiệm lập phương thức vận hành hàng tuần, hàng ngày."},
{id:93,q:"Theo TT06/2025/TT-BCT: Trong quá trình thao tác nếu có cảnh báo bất thường xảy ra, nhân viên vận hành phải:",opts:["Báo cáo người ra lệnh","Tiếp tục thao tác và báo cáo sau","Ngừng thao tác và báo cáo người ra lệnh để xử lý trước khi tiếp tục","Tự quyết định phương án xử lý"],ans:2,explain:"Khi có cảnh báo bất thường trong quá trình thao tác, phải ngừng thao tác và báo cáo người ra lệnh để xử lý."},
{id:94,q:"Theo TT06/2025/TT-BCT: Quy định về kiểm tra thiết bị tại trạm điện:",opts:["Phải kiểm tra định kỳ ít nhất 01 lần/ca trực","Phải kiểm tra 02 lần/ca trực","Phải kiểm tra theo yêu cầu lãnh đạo","Không quy định cụ thể số lần kiểm tra"],ans:0,explain:"Theo quy định, phải kiểm tra thiết bị ít nhất 01 lần/ca trực."},
{id:95,q:"Theo TT06/2025/TT-BCT: Thẩm quyền phê duyệt phương án khởi động đen và khôi phục hệ thống điện miền cấp 110kV thuộc về?",opts:["Cục điều tiết điện lực","EVN","Cấp điều độ quốc gia","Cấp điều độ miền"],ans:2,explain:"Cấp điều độ quốc gia phê duyệt phương án khởi động đen và khôi phục hệ thống điện miền cấp 110kV."},
{id:96,q:"Theo TT06/2025/TT-BCT: Điều kiện hòa đồng bộ tại điểm đấu nối cấp điện áp 500kV là:",opts:["Góc lệch pha ≤ 15 độ, chênh lệch tần số ≤ 0,05 Hz, chênh lệch điện áp ≤ 3%","Góc lệch pha ≤ 20 độ, chênh lệch tần số ≤ 0,10 Hz, chênh lệch điện áp ≤ 5%","Góc lệch pha ≤ 25 độ, chênh lệch tần số ≤ 0,20 Hz, chênh lệch điện áp ≤ 8%","Góc lệch pha ≤ 30 độ, chênh lệch tần số ≤ 0,25 Hz, chênh lệch điện áp ≤ 10%"],ans:0,explain:"Điều kiện hòa đồng bộ 500kV: góc lệch pha ≤ 15 độ, chênh lệch tần số ≤ 0,05 Hz, chênh lệch điện áp ≤ 3%."},
{id:97,q:"Theo TT06/2025/TT-BCT: Khi mất liên lạc với cấp điều độ có quyền điều khiển, nhân viên vận hành phải xử lý như thế nào?",opts:["Tự quyết định phương án vận hành","Chờ liên lạc được mới thao tác","Báo cáo lãnh đạo trực tiếp để xin ý kiến","Tiếp tục vận hành giữ nguyên trạng thái thiết bị và báo cáo"],ans:0,explain:"Khi mất liên lạc, NVVH tự quyết định phương án vận hành và duy trì an toàn hệ thống."},
{id:98,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng về thời hạn cấp chứng nhận vận hành?",opts:["Chứng nhận vận hành có thời hạn 03 năm","Chứng nhận vận hành có thời hạn 05 năm","Chứng nhận vận hành không có thời hạn","Chứng nhận vận hành có thời hạn 02 năm"],ans:0,explain:"Chứng nhận vận hành có thời hạn 03 năm theo TT06."},
{id:99,q:"Theo TT06/2025/TT-BCT: Nhân viên vận hành được phép làm những điều gì trong thời gian trực ca?",opts:["Đọc sách, báo không liên quan đến công việc","Sử dụng điện thoại cá nhân","Học tài liệu liên quan đến công việc với sự cho phép của Trưởng kíp","Ngủ trong giờ trực"],ans:2,explain:"NVVH được phép học tài liệu liên quan đến công việc khi được Trưởng kíp cho phép."},
{id:100,q:"Theo TT06/2025/TT-BCT: Chứng nhận vận hành chức danh Trưởng kíp trạm điện được cấp bởi đơn vị nào?",opts:["Cục Điều tiết điện lực","Tập đoàn Điện lực Việt Nam","Cấp điều độ quốc gia","Cấp điều độ miền"],ans:2,explain:"Cấp điều độ quốc gia tổ chức kiểm tra và cấp Chứng nhận vận hành cho Trưởng kíp trạm điện."},
{id:101,q:"Theo TT06/2025/TT-BCT, Nhân viên vận hành bao gồm những đối tượng sau:",opts:["Điều độ viên tại các cấp điều độ, Trưởng ca nhà máy điện, Trưởng kíp trạm điện","Nhân viên trực thao tác lưu động","Nhân viên được giao nhiệm vụ tại trung tâm điều khiển","Tất cả các đối tượng trên"],ans:3,explain:"Nhân viên vận hành bao gồm tất cả các đối tượng A, B, C."},
{id:102,q:"Theo TT06/2025/TT-BCT: Phương án nào đúng khi thực hiện thao tác đóng điện đường dây mới?",opts:["Dùng máy cắt và rơ le bảo vệ dự phòng đã được chỉnh định để đóng điện đường dây lần đầu","Không cần khóa mạch tự động đóng lại","Kiểm tra điều kiện đồng bộ trước khi đóng điện đường dây","Không cần kiểm tra đúng thứ tự pha"],ans:0,explain:"Đóng điện đường dây mới phải dùng máy cắt và rơ le bảo vệ dự phòng đã được chỉnh định."},
{id:103,q:"Theo TT06/2025/TT-BCT: Khi thao tác mở máy cắt, nhân viên vận hành phải làm gì sau đó?",opts:["Báo cáo trưởng kíp","Kiểm tra trạng thái máy cắt","Ghi nhật ký và kiểm tra thông số","Tất cả các phương án trên"],ans:2,explain:"Sau khi thao tác mở máy cắt, phải ghi nhật ký vận hành và kiểm tra các thông số liên quan."},
{id:104,q:"Theo TT06/2025/TT-BCT: Trình tự thao tác tách đường dây để sửa chữa:",opts:["Cắt máy cắt → mở dao cách ly → đóng dao tiếp địa","Mở dao cách ly → cắt máy cắt → đóng dao tiếp địa","Đóng dao tiếp địa → cắt máy cắt → mở dao cách ly","Cắt máy cắt → đóng dao tiếp địa → mở dao cách ly"],ans:0,explain:"Trình tự tách đường dây: Cắt máy cắt → mở dao cách ly → đóng dao tiếp địa."},
{id:105,q:"Theo TT06/2025/TT-BCT: Thao tác đóng điện lại đường dây sau sửa chữa:",opts:["Cắt dao tiếp địa → đóng dao cách ly → đóng máy cắt","Đóng máy cắt → cắt dao tiếp địa → đóng dao cách ly","Đóng dao cách ly → đóng máy cắt → cắt dao tiếp địa","Cắt dao tiếp địa → đóng máy cắt → đóng dao cách ly"],ans:0,explain:"Trình tự đóng điện đường dây sau sửa chữa: Cắt dao tiếp địa → đóng dao cách ly → đóng máy cắt."},
{id:106,q:"Theo TT05/2025/TT-BCT: Tần số định mức của lưới điện Việt Nam là:",opts:["50 Hz","60 Hz","45 Hz","55 Hz"],ans:0,explain:"Tần số định mức của lưới điện Việt Nam là 50 Hz."},
{id:107,q:"Theo TT06/2025/TT-BCT: Thời gian lưu trữ phiếu thao tác sau khi thực hiện xong là:",opts:["ít nhất 03 tháng","ít nhất 06 tháng","ít nhất 01 năm","ít nhất 05 năm"],ans:1,explain:"Phiếu thao tác được lưu trữ ít nhất 06 tháng sau khi thực hiện xong."},
{id:108,q:"Theo TT06/2025/TT-BCT: Khi phát hiện có rò rỉ khí SF6 ở máy cắt, nhân viên vận hành phải:",opts:["Báo cáo ngay cấp điều độ có quyền điều khiển và lãnh đạo trực tiếp","Tự xử lý","Tiếp tục vận hành bình thường","Cắt máy cắt ngay"],ans:0,explain:"Khi phát hiện rò rỉ khí SF6, phải báo cáo ngay cấp điều độ có quyền điều khiển và lãnh đạo trực tiếp."},
{id:109,q:"Theo TT06/2025/TT-BCT: Phiếu thao tác theo kế hoạch phải được chuyển tới nhân viên vận hành trước thời gian bắt đầu thao tác:",opts:["60 phút","120 phút","90 phút","45 phút"],ans:2,explain:"Phiếu thao tác kế hoạch phải chuyển tới NVVH trước ít nhất 90 phút so với giờ bắt đầu thao tác."},
{id:110,q:"Theo TT06/2025/TT-BCT: Người nào có thể giám sát thao tác tại cấp điều độ miền?",opts:["Điều độ viên phụ trách ca trực","Trưởng phòng Điều độ","Phó Giám đốc phụ trách kỹ thuật","Tất cả các phương án trên"],ans:2,explain:"Tại cấp điều độ miền, người giám sát thao tác là Phó Giám đốc phụ trách kỹ thuật trở lên."},
{id:111,q:"Theo TT06/2025/TT-BCT: Điều độ viên cấp điều độ quốc gia có quyền:",opts:["Ra lệnh điều độ cho nhân viên vận hành trong phạm vi quyền điều khiển","Kiểm tra việc thực hiện lệnh điều độ","Đình chỉ thao tác khi phát hiện vi phạm an toàn","Tất cả các quyền trên"],ans:3,explain:"Điều độ viên cấp điều độ quốc gia có cả 3 quyền A, B, C."},
{id:112,q:"Theo TT05/2025/TT-BCT: Giới hạn dòng điện ngắn mạch lớn nhất cho phép ở cấp 220kV:",opts:["40 kA","50 kA","63 kA","80 kA"],ans:0,explain:"Dòng điện ngắn mạch lớn nhất cho phép ở cấp 220kV là 40 kA."},
{id:113,q:"Theo TT06/2025/TT-BCT: Biểu đồ điện áp do đơn vị nào ban hành?",opts:["EVN","Đơn vị QLVH tự ban hành","Cấp điều độ có quyền điều khiển ban hành","Cục Điều tiết điện lực"],ans:2,explain:"Biểu đồ điện áp do Cấp điều độ có quyền điều khiển ban hành."},
{id:114,q:"Theo TT06/2025/TT-BCT: Quy định về giao nhận ca trong điều kiện sự cố:",opts:["Không giao nhận ca khi đang xử lý sự cố","Phải hoàn thành xử lý sự cố trước khi giao nhận ca","Giao nhận ca khi sự cố đã qua giai đoạn cấp bách, đã xác định được phương án xử lý","Giao nhận ca bình thường không phụ thuộc vào trạng thái sự cố"],ans:1,explain:"Phải hoàn thành xử lý sự cố trước khi giao nhận ca."},
{id:115,q:"Theo TT06/2025/TT-BCT: Thời gian đào tạo Trưởng ca nhà máy điện có tổng công suất đặt lớn hơn 1000 MW:",opts:["ít nhất 06 tháng","ít nhất 12 tháng","ít nhất 18 tháng","ít nhất 24 tháng"],ans:2,explain:"Thời gian đào tạo Trưởng ca NMĐ có công suất trên 1000 MW là ít nhất 18 tháng."},
{id:116,q:"Theo TT06/2025/TT-BCT: Đơn vị nào có trách nhiệm xây dựng trình tự kiểm tra và cấp chứng nhận vận hành?",opts:["Đơn vị Điều độ hệ thống điện quốc gia","Cục Điều tiết điện lực","Bộ Công Thương","Tập Đoàn Điện lực"],ans:0,explain:"Đơn vị Điều độ hệ thống điện quốc gia (A0) có trách nhiệm xây dựng trình tự kiểm tra và cấp chứng nhận vận hành."},
{id:117,q:"Theo TT06/2025/TT-BCT: Khi có tín hiệu bảo vệ hơi tác động cảnh báo ở máy biến áp, nhân viên vận hành phải:",opts:["Cắt ngay máy biến áp ra khỏi vận hành","Lấy mẫu khí để phân tích tính chất cháy, báo cáo cấp điều độ và lãnh đạo trực tiếp","Tiếp tục vận hành và theo dõi","Chờ lệnh của cấp điều độ"],ans:1,explain:"Khi bảo vệ hơi tác động cảnh báo, phải lấy mẫu khí phân tích tính chất cháy, báo cáo cấp điều độ và lãnh đạo trực tiếp."},
{id:118,q:"Theo TT06/2025/TT-BCT: Ai có thẩm quyền phê duyệt phương án khởi động đen và khôi phục HTĐ QG cấp điện áp từ 220kV trở lên?",opts:["Cấp điều độ quốc gia","EVN","Bộ Công Thương","Cục Điều tiết điện lực"],ans:3,explain:"Cục Điều tiết điện lực phê duyệt phương án khởi động đen và khôi phục HTĐ QG cấp điện áp từ 220kV trở lên."},
{id:119,q:"Theo TT06/2025/TT-BCT: Khi nghi ngờ thiết bị có khiếm khuyết, nhân viên vận hành phải:",opts:["Tiếp tục vận hành và theo dõi","Báo cáo ngay cho cấp điều độ và lãnh đạo trực tiếp","Tự xử lý khiếm khuyết","Đề xuất cắt điện thiết bị"],ans:1,explain:"Khi nghi ngờ thiết bị có khiếm khuyết, phải báo cáo ngay cho cấp điều độ và lãnh đạo trực tiếp."},
{id:120,q:"Theo TT06/2025/TT-BCT: Đơn vị nào có trách nhiệm xây dựng kế hoạch khởi động đen hàng năm?",opts:["Cấp điều độ quốc gia","Cấp điều độ miền","EVN","Đơn vị phát điện"],ans:0,explain:"Cấp điều độ quốc gia có trách nhiệm xây dựng kế hoạch khởi động đen hàng năm."},
{id:121,q:"Theo TT06/2025/TT-BCT: Trưởng kíp trạm điện có trách nhiệm gì khi nhận lệnh thao tác từ cấp điều độ?",opts:["Thực hiện ngay lệnh mà không cần kiểm tra","Hỏi lại lệnh và xác nhận trước khi thực hiện","Báo cáo lãnh đạo trực tiếp trước khi thực hiện","Lập phiếu thao tác rồi mới báo cáo cấp điều độ"],ans:3,explain:"Trưởng kíp phải lập phiếu thao tác trước khi thực hiện lệnh điều độ (trong các trường hợp yêu cầu phiếu thao tác)."},
{id:122,q:"Theo TT06/2025/TT-BCT: Điều kiện để đóng lại đường dây bị sự cố 1 pha ở cấp điện áp 220kV là:",opts:["Đóng lại ngay","Sau khi cấp điều độ xem xét và cho lệnh","Chỉ đóng lại nếu không có công tác sửa chữa nóng và không có bão từ cấp 6 trở lên","Không đóng lại"],ans:0,explain:"Đường dây 220kV bị sự cố 1 pha, TĐLL thành công thì đóng lại ngay."},
{id:123,q:"Theo TT06/2025/TT-BCT: Số người tối thiểu thực hiện thao tác tại vị trí đặt thiết bị điện nhất thứ là:",opts:["1 người","2 người","3 người","4 người"],ans:1,explain:"Thao tác tại vị trí đặt thiết bị điện nhất thứ phải có tối thiểu 2 người (1 người thao tác, 1 người giám sát)."},
{id:124,q:"Theo TT06/2025/TT-BCT: Quy định về thời gian giao nhận ca tại cấp điều độ miền:",opts:["Không quá 15 phút","Không quá 30 phút","Không quá 45 phút","Không quy định thời gian"],ans:0,explain:"Giao nhận ca tại cấp điều độ miền không quá 15 phút."},
{id:125,q:"Theo TT06/2025/TT-BCT: Khi xảy ra sự cố, điều độ viên miền phải:",opts:["Xử lý sự cố theo phương án đã được phê duyệt và báo cáo cấp điều độ quốc gia","Chờ lệnh cấp điều độ quốc gia mới xử lý","Tự quyết định phương án xử lý","Báo cáo lãnh đạo để xin ý kiến"],ans:0,explain:"Điều độ viên miền xử lý sự cố theo phương án đã được phê duyệt và báo cáo cấp điều độ quốc gia."},
{id:126,q:"Theo TT05/2025/TT-BCT: Dải tần số vận hành bình thường của hệ thống điện quốc gia:",opts:["49,8 Hz đến 50,2 Hz","49,5 Hz đến 50,5 Hz","49,0 Hz đến 51,0 Hz","49,7 Hz đến 50,3 Hz"],ans:0,explain:"Dải tần số vận hành bình thường: 49,8 Hz đến 50,2 Hz."},
{id:127,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng thời gian phiếu thao tác theo kế hoạch phải được chuyển tới nhân viên vận hành trực tiếp?",opts:["Trước 60 phút","Trước 90 phút","Trước 120 phút","Trước 30 phút"],ans:2,explain:"Phiếu thao tác kế hoạch phải được chuyển tới NVVH trước 120 phút."},
{id:128,q:"Theo TT06/2025/TT-BCT: Sơ đồ một sợi của trạm điện phải được:",opts:["Cập nhật ngay sau mỗi lần thay đổi kết dây","Cập nhật 01 lần/năm","Cập nhật 02 lần/năm","Cập nhật theo yêu cầu của cấp điều độ"],ans:0,explain:"Sơ đồ một sợi phải được cập nhật ngay sau mỗi lần thay đổi kết dây."},
{id:129,q:"Theo TT06/2025/TT-BCT: Nhân viên vận hành được phép từ chối lệnh điều độ trong trường hợp nào?",opts:["Khi lệnh điều độ trái với quy trình kỹ thuật","Khi lệnh điều độ đe dọa đến an toàn thiết bị","Khi lệnh điều độ đe dọa đến tính mạng con người","Cả B và C"],ans:3,explain:"NVVH được phép từ chối lệnh điều độ khi lệnh đó đe dọa đến tính mạng con người hoặc an toàn thiết bị."},
{id:130,q:"Theo TT06/2025/TT-BCT: Phương án nào không đúng về quyền của nhân viên vận hành?",opts:["Được từ chối lệnh điều độ khi nguy hiểm đến tính mạng","Được tự ý thay đổi sơ đồ kết dây mà không cần lệnh","Được báo cáo khi phát hiện lệnh điều độ không an toàn","Được đề xuất phương án xử lý sự cố"],ans:1,explain:"Nhân viên vận hành không được tự ý thay đổi sơ đồ kết dây mà không có lệnh điều độ."},
{id:131,q:"Theo TT06/2025/TT-BCT: Trường hợp nào sau đây bắt buộc phải lập phiếu thao tác?",opts:["Thao tác thay đổi nấc phân áp MBA","Thao tác tự động đóng lại","Thao tác có từ 04 bước thao tác trở lên","Tất cả các trường hợp"],ans:2,explain:"Bắt buộc phải lập phiếu thao tác khi có từ 04 bước thao tác trở lên (hoặc từ 03 bước thao tác trở lên khi thao tác bằng tay tại chỗ)."},
{id:132,q:"Theo TT06/2025/TT-BCT: Báo cáo vận hành ngày của trạm điện phải gửi trước mấy giờ?",opts:["Trước 5:00","Trước 6:00","Trước 6:30","Trước 7:00"],ans:3,explain:"Báo cáo vận hành ngày tại trạm điện phải gửi trước 7:00."},
{id:133,q:"Theo TT06/2025/TT-BCT: Người giám sát thao tác tại chỗ phải có bậc an toàn tối thiểu là:",opts:["Bậc 2","Bậc 3","Bậc 4","Bậc 5"],ans:0,explain:"Người giám sát thao tác tại chỗ phải có bậc an toàn tối thiểu là bậc 3 trở lên."},
{id:134,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng về thời gian lưu trữ phiếu thao tác không thực hiện được?",opts:["ít nhất 01 tháng","ít nhất 03 tháng","ít nhất 06 tháng","ít nhất 01 năm"],ans:0,explain:"Phiếu thao tác không thực hiện được lưu trữ ít nhất 01 tháng."},
{id:135,q:"Theo TT06/2025/TT-BCT: Tổ máy phát của NMĐ đấu nối vào lưới điện 500kV thuộc quyền điều khiển của:",opts:["Cấp điều độ quốc gia","Cấp điều độ miền","Đơn vị phát điện","Không quy định"],ans:1,explain:"Tổ máy phát đấu nối vào lưới điện 500kV thuộc quyền điều khiển của Cấp điều độ miền."},
{id:136,q:"Theo TT06/2025/TT-BCT: Khi hệ thống điện vận hành ở chế độ khẩn cấp, cấp điều độ quốc gia có thể:",opts:["Sa thải phụ tải có chọn lọc","Yêu cầu NMĐ phát tối đa công suất","Cả A và B","Không làm gì cả, chờ tự phục hồi"],ans:2,explain:"Khi chế độ khẩn cấp, cấp điều độ quốc gia có thể sa thải phụ tải có chọn lọc và yêu cầu NMĐ phát tối đa công suất."},
{id:137,q:"Theo TT05/2025/TT-BCT: Giá trị điện áp trên lưới 500kV không được vượt quá:",opts:["550 kV","545 kV","525 kV","540 kV"],ans:0,explain:"Điện áp trên lưới 500kV không được vượt quá 550 kV theo TT05."},
{id:138,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng về việc cho phép nhân viên không liên quan vào phòng điều khiển?",opts:["Không cho phép bất kỳ ai vào phòng điều khiển khi không có nhiệm vụ","Chỉ cho phép khi có lệnh của lãnh đạo trực tiếp","Trưởng kíp được phép cho phép các nhân viên liên quan công tác vào phòng điều khiển","Không quy định"],ans:3,explain:"Không quy định cụ thể về việc cho phép người không liên quan vào phòng điều khiển, nhưng phải đảm bảo an toàn và bảo mật."},
{id:139,q:"Theo TT06/2025/TT-BCT: Đơn vị nào chịu trách nhiệm xây dựng quy trình vận hành hệ thống điện thuộc quyền điều khiển?",opts:["Cấp điều độ có quyền điều khiển","Đơn vị QLVH","EVN","Cục Điều tiết điện lực"],ans:2,explain:"Cấp điều độ có quyền điều khiển chịu trách nhiệm xây dựng quy trình vận hành hệ thống điện thuộc quyền điều khiển."},
{id:140,q:"Theo TT06/2025/TT-BCT: Khi xảy ra sự cố nghiêm trọng, ai là người chủ trì phương án xử lý?",opts:["Giám đốc đơn vị QLVH","Điều độ viên cấp điều độ có quyền điều khiển","Trưởng kíp trạm điện","Lãnh đạo trực tiếp của trạm điện"],ans:1,explain:"Điều độ viên cấp điều độ có quyền điều khiển là người chủ trì phương án xử lý sự cố."},
{id:141,q:"Theo TT06/2025/TT-BCT: Chứng nhận vận hành bị thu hồi trong trường hợp nào?",opts:["Chứng nhận hết hạn","Nhân viên nghỉ việc","Nhân viên vi phạm nghiêm trọng quy định về an toàn điện","Tất cả các trường hợp trên"],ans:2,explain:"Chứng nhận vận hành bị thu hồi khi nhân viên vi phạm nghiêm trọng quy định về an toàn điện."},
{id:142,q:"Theo TT06/2025/TT-BCT: Khi nào được phép sử dụng tiếp địa di động thay thế dao tiếp địa cố định?",opts:["Khi dao tiếp địa cố định bị hỏng","Khi được lãnh đạo đơn vị cho phép","Khi được cấp điều độ cho phép","Khi được cả lãnh đạo đơn vị và cấp điều độ cho phép"],ans:0,explain:"Tiếp địa di động được sử dụng thay thế dao tiếp địa cố định khi dao bị hỏng."},
{id:143,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng về ứng trực của nhân viên vận hành?",opts:["NVVH phải ứng trực 24/7 khi được yêu cầu","NVVH chỉ làm việc theo ca trực","NVVH có thể được triệu tập khi cần trong thời gian nghỉ","Không quy định về ứng trực"],ans:2,explain:"NVVH có thể được triệu tập khi cần thiết trong thời gian nghỉ."},
{id:144,q:"Theo TT06/2025/TT-BCT: Khi máy biến áp bị quá tải, nhân viên vận hành phải theo dõi những thông số nào?",opts:["Nhiệt độ cuộn dây, nhiệt độ dầu","Dòng điện qua máy biến áp","Điện áp hai phía máy biến áp","Tất cả các thông số trên"],ans:0,explain:"Khi MBA quá tải phải theo dõi chặt chẽ nhiệt độ cuộn dây và nhiệt độ dầu MBA."},
{id:145,q:"Theo TT05/2025/TT-BCT: Dải tần số vận hành ở chế độ bình thường của hệ thống điện là:",opts:["49,5 Hz đến 50,5 Hz","49,8 Hz đến 50,2 Hz","49,0 Hz đến 51,0 Hz","Không quy định"],ans:3,explain:"TT05 quy định dải tần số vận hành bình thường là 49,8 Hz đến 50,2 Hz (nhưng câu hỏi hỏi 'Không quy định' - cần kiểm tra lại theo đề gốc)."},
{id:146,q:"Theo TT06/2025/TT-BCT: Nhân viên vận hành thực hiện thao tác theo phiếu thao tác có thể:",opts:["Bỏ qua bước thao tác nếu thấy không cần thiết","Đảo ngược thứ tự thao tác khi cần","Chỉ thực hiện theo đúng thứ tự ghi trong phiếu thao tác","Tự bổ sung bước thao tác mà không cần phê duyệt"],ans:3,explain:"Có thể tự bổ sung các bước thao tác mạch nhị thứ vào phiếu theo quy định."},
{id:147,q:"Theo TT06/2025/TT-BCT: Ai là người ký xác nhận hoàn thành thao tác trong phiếu thao tác?",opts:["Người duyệt phiếu","Trưởng kíp","Người thực hiện thao tác","Điều độ viên"],ans:0,explain:"Người duyệt phiếu ký xác nhận hoàn thành thao tác trong phiếu thao tác."},
{id:148,q:"Theo TT06/2025/TT-BCT: Khi mất điện toàn bộ trạm, nhân viên vận hành phải làm gì đầu tiên?",opts:["Cắt tất cả máy cắt","Báo cáo cấp điều độ và lãnh đạo trực tiếp ngay","Kiểm tra nguồn tự dùng DC","Tất cả các phương án trên đều sai, phải đóng lại nguồn điện"],ans:3,explain:"Khi mất điện toàn bộ trạm, ưu tiên báo cáo cấp điều độ và lãnh đạo, kiểm tra nguồn DC và cắt các máy cắt chưa cắt."},
{id:149,q:"Theo TT06/2025/TT-BCT: Định nghĩa về 'quyền điều khiển' là:",opts:["Quyền ra lệnh thay đổi trạng thái hoặc thông số vận hành thiết bị","Quyền kiểm tra vận hành thiết bị","Quyền lập kế hoạch sửa chữa thiết bị","Quyền cấp phép công tác cho đội sửa chữa"],ans:0,explain:"Quyền điều khiển là quyền ra lệnh thay đổi trạng thái hoặc thông số vận hành thiết bị điện."},
{id:150,q:"Theo TT06/2025/TT-BCT: Phương án nào đúng về thứ tự điều chỉnh điện áp hệ thống?",opts:["Điều chỉnh từ gần đến xa điểm cần điều chỉnh điện áp","Điều chỉnh từ xa đến gần điểm cần điều chỉnh điện áp","Điều chỉnh đồng thời tất cả các điểm","Không quy định thứ tự"],ans:0,explain:"Thứ tự điều chỉnh điện áp từ gần đến xa điểm cần điều chỉnh."},
{id:151,q:"Theo TT06/2025/TT-BCT: Nhân viên vận hành cấp trên tại cấp điều độ miền là ai?",opts:["Điều độ viên phân phối","Điều độ viên quốc gia","Trưởng ca nhà máy điện","Trưởng kíp trạm điện"],ans:1,explain:"Điều độ viên quốc gia là NVVH cấp trên của Điều độ viên miền."},
{id:152,q:"Theo TT06/2025/TT-BCT: Khi sự cố đường dây có tính chất thoáng qua ở cấp điện áp 220kV, xử lý như thế nào?",opts:["Không đóng lại","Đóng lại tự động 01 lần","Đóng lại bằng tay 01 lần","Đóng lại theo lệnh cấp điều độ"],ans:3,explain:"Đóng lại đường dây 220kV bị sự cố theo lệnh của cấp điều độ có quyền điều khiển."},
{id:153,q:"Theo TT06/2025/TT-BCT: Điều kiện để khép vòng cấp điện áp 220kV:",opts:["Không cần điều kiện gì","Chênh lệch điện áp ≤ 22 kV và góc lệch pha ≤ 30 độ","Chênh lệch điện áp ≤ 10% và góc lệch pha ≤ 15 độ","Chỉ cần được lệnh cấp điều độ"],ans:1,explain:"Điều kiện khép vòng 220kV: chênh lệch điện áp ≤ 22 kV và góc lệch pha ≤ 30 độ."},
{id:154,q:"Theo TT06/2025/TT-BCT: Ai được phép gia hạn phiếu thao tác?",opts:["Người duyệt phiếu","Người viết phiếu","Điều độ viên cấp điều độ có quyền điều khiển","Trưởng kíp trạm điện"],ans:0,explain:"Người duyệt phiếu có thẩm quyền gia hạn phiếu thao tác."},
{id:155,q:"Theo TT06/2025/TT-BCT: Quy định về bảo trì thiết bị điện theo mùa trong hệ thống điện:",opts:["Thực hiện trước mùa cao điểm dùng điện","Thực hiện theo kế hoạch được cấp điều độ phê duyệt","Thực hiện bất kỳ khi nào thiết bị có vấn đề","Không quy định cụ thể"],ans:1,explain:"Bảo trì thiết bị điện thực hiện theo kế hoạch được cấp điều độ phê duyệt."},
{id:156,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng về việc cấp điều độ quốc gia điều khiển tần số?",opts:["Qua lệnh điều độ bằng lời nói","Qua hệ thống AGC","Qua tín hiệu điều khiển từ xa","Tất cả các phương án trên"],ans:3,explain:"Cấp điều độ quốc gia điều khiển tần số qua tất cả các hình thức: lệnh điều độ, hệ thống AGC và tín hiệu điều khiển từ xa."},
{id:157,q:"Theo TT06/2025/TT-BCT: Thao tác dao cách ly chỉ được phép thực hiện khi:",opts:["Máy cắt tương ứng đang ở trạng thái đóng","Máy cắt tương ứng đang ở trạng thái mở","Không phụ thuộc trạng thái máy cắt","Khi có lệnh điều độ"],ans:1,explain:"Thao tác dao cách ly chỉ được phép thực hiện khi máy cắt tương ứng đang ở trạng thái mở."},
{id:158,q:"Theo TT06/2025/TT-BCT: Khi có lệnh điều độ bằng điện thoại, nhân viên vận hành phải:",opts:["Thực hiện ngay","Ghi vào sổ nhật ký và thực hiện","Đọc lại lệnh để xác nhận rồi thực hiện","Lập phiếu thao tác rồi thực hiện"],ans:1,explain:"Khi nhận lệnh điều độ bằng điện thoại, phải ghi vào sổ nhật ký vận hành và thực hiện theo lệnh."},
{id:159,q:"Theo TT06/2025/TT-BCT: Quyền điều kiển của Cấp điều độ quốc gia đối với đường dây truyền tải:",opts:["Chỉ đường dây 500kV","Chỉ đường dây 500kV và 220kV","Tất cả đường dây từ 110kV trở lên","Đường dây từ 220kV trở lên"],ans:0,explain:"Cấp điều độ quốc gia có quyền điều khiển đường dây 500kV."},
{id:160,q:"Theo TT06/2025/TT-BCT: Điều kiện để hòa đồng bộ ở cấp điện áp 220kV:",opts:["Góc lệch pha điện áp không quá 15 độ, chênh lệch tần số không quá 0,05 Hz, chênh lệch điện áp không quá 5%.","Góc lệch pha điện áp không quá 15 độ, chênh lệch tần số không quá 0,10 Hz, chênh lệch điện áp không quá 10%.","Góc lệch pha điện áp không quá 30 độ, chênh lệch tần số không quá 0,25 Hz, chênh lệch điện áp không quá 10%.","Đồng tần, đồng áp, đồng pha"],ans:2,explain:"Điều kiện hòa đồng bộ 220kV: góc lệch pha ≤ 30 độ, chênh lệch tần số ≤ 0,25 Hz, chênh lệch điện áp ≤ 10%."},
{id:161,q:"Theo TT05/2025/TT-BCT, quy định về cân bằng pha ở chế độ vận hành bình thường của điện áp cao áp và siêu cao áp:",opts:["Thành phần thứ tự nghịch của điện áp pha không được vượt quá 05% điện áp danh định","Thành phần thứ tự nghịch của điện áp pha không được vượt quá 04% điện áp danh định","Thành phần thứ tự nghịch của điện áp pha không được vượt quá 03% điện áp danh định","Thành phần thứ tự nghịch của điện áp pha không được vượt quá 02% điện áp danh định"],ans:3,explain:"Thành phần thứ tự nghịch của điện áp pha không được vượt quá 02% điện áp danh định ở chế độ bình thường."},
{id:162,q:"Theo TT06/2025/TT-BCT: Quy định trách nhiệm của Nhân viên vận hành trực ban trung gian khi truyền lệnh?",opts:["Phải ghi âm, ghi chép lệnh đầy đủ vào sổ và chuyển ngay lệnh đến đúng người nhận lệnh","Phải chuyển ngay lệnh đến đúng người nhận lệnh. Nếu không liên lạc được với người nhận lệnh, phải báo lại ngay cho người ra lệnh biết","Phải ghi âm, ghi chép lệnh đầy đủ vào sổ và chuyển ngay lệnh đến đúng người nhận lệnh. Nếu không liên lạc được với người nhận lệnh, phải báo lại ngay cho người ra lệnh biết","Không quy định"],ans:2,explain:"NVVH trực ban trung gian phải ghi âm, ghi chép và chuyển lệnh ngay. Nếu không liên lạc được người nhận lệnh phải báo lại ngay người ra lệnh."},
{id:163,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định đúng cấp điện áp cho phép đóng lại ngay đường dây hỗn hợp trên không và cáp sau khi nhảy sự cố?",opts:["Cấp điện áp đến 220kV","Cấp điện áp đến 110kV","Cấp điện áp đến 35kV","Không cho phép đóng lại"],ans:2,explain:"Đường dây hỗn hợp trên không và cáp ở cấp điện áp đến 35kV mới được phép đóng lại ngay sau sự cố."},
{id:164,q:"Theo TT06/2025/TT-BCT: Việc ban hành quy trình thao tác thiết bị điện thuộc phạm vi quản lý phù hợp với yêu cầu của nhà chế tạo thuộc trách nhiệm của?",opts:["Đơn vị quản lý vận hành","Cấp Điều độ có quyền điều khiển","Không quy định","Cả A & B"],ans:0,explain:"Đơn vị quản lý vận hành có trách nhiệm ban hành quy trình thao tác thiết bị điện thuộc phạm vi quản lý."},
{id:165,q:"Theo TT06/2025/TT-BCT: Quy định ghi số phiếu thao tác đột xuất trong tháng tại điều độ miền đúng theo phương án nào?",opts:["Số TT phiếu ĐX trong năm / năm phát hành phiếu / ĐX / tên viết tắt cấp điều độ miền","Số TT phiếu ĐX trong tháng / tháng phát hành phiếu / ĐX / tên viết tắt trạm","ĐX / số TT phiếu ĐX trong năm / năm phát hành phiếu / tên viết tắt công ty","Tên viết tắt cấp điều độ miền / ĐX / số TT phiếu KH trong năm / năm phát hành"],ans:0,explain:"Ghi theo thứ tự: Số TT phiếu ĐX trong năm / năm phát hành / ĐX / tên viết tắt cấp điều độ miền."},
{id:166,q:"Theo TT06/2025/TT-BCT: Phiếu thao tác không được hủy trong trường hợp nào?",opts:["Thao tác có xảy ra sự cố hoặc tai nạn","Thao tác đóng điện công trình mới","Thao tác xử lý sự cố","Không quy định"],ans:0,explain:"Phiếu thao tác không được hủy khi thao tác có xảy ra sự cố hoặc tai nạn."},
{id:167,q:"Theo TT06/2025/TT-BCT, Việc cô lập hoặc đưa các rơ le bảo vệ và tự động vào vận hành trở lại chỉ được thực hiện khi có mệnh lệnh cho phép của?",opts:["Điều độ viên cấp điều độ có quyền điều khiển.","Điều độ viên cấp điều độ có quyền kiểm tra.","Lãnh đạo đơn vị quản lý vận hành.","Lãnh đạo cấp điều độ có quyền điều khiển."],ans:0,explain:"Cô lập hoặc đưa rơ le bảo vệ vào vận hành trở lại phải có mệnh lệnh cho phép của Điều độ viên cấp điều độ có quyền điều khiển."},
{id:168,q:"Theo TT06/2025/TT-BCT: Điều kiện cần có để thực hiện trong phiếu thao tác thiết bị điện do nhà máy lập phiếu thao tác ghi đúng theo phương án nào:",opts:["Ghi lại điều kiện do Điều độ viên có quyền điều khiển yêu cầu.","Ghi những biện pháp an toàn cần phải thực hiện","Ghi rõ những điều kiện bắt buộc phải có mới được thực hiện thao tác","Để trống, không cần ghi"],ans:2,explain:"Phải ghi rõ những điều kiện bắt buộc phải có mới được thực hiện thao tác vào phiếu thao tác."},
{id:169,q:"Theo TT06/2025/TT-BCT, Nếu không có quy định riêng, MBA được phép vận hành lâu dài với điện áp cao hơn 10% điện áp định mức trong điều kiện nào?",opts:["Nhiệt độ dầu máy biến áp không vượt quá 60 độ C","Tải qua máy biến áp không quá 25% công suất định mức","Tải qua máy biến áp không quá 30% công suất định mức","Nhiệt độ cuộn dây máy biến áp không vượt quá 80 độ C"],ans:1,explain:"MBA được vận hành với điện áp cao hơn 10% khi tải qua MBA không quá 25% công suất định mức."},
{id:170,q:"Theo TT06/2025/TT-BCT: Thao tác đóng, cắt máy cắt phải thực hiện theo?",opts:["Quy định của nhà chế tạo","Quy trình thao tác thiết bị điện do Đơn vị quản lý vận hành ban hành","Quy định của cấp điều độ có quyền điều khiển","A hoặc B"],ans:3,explain:"Thao tác đóng cắt máy cắt thực hiện theo quy định của nhà chế tạo (A) hoặc quy trình thao tác do ĐVQLVH ban hành (B)."},
{id:171,q:"Theo TT05/2025/TT-BCT, định nghĩa đúng về hệ thống AGC:",opts:["Là hệ thống thiết bị tự động điều chỉnh tăng giảm công suất tác dụng của tổ máy phát điện, nhà máy điện, cụm nhà máy điện hoặc hệ thống pin tích trữ nhằm đảm bảo vận hành an toàn, ổn định hệ thống điện","Là hệ thống thiết bị tự động điều chỉnh tăng giảm công suất phản kháng của tổ máy phát điện, nhà máy điện, cụm nhà máy điện hoặc hệ thống pin tích trữ nhằm đảm bảo vận hành an toàn","Là hệ thống thiết bị tự động điều chỉnh tăng giảm công suất tác dụng của tổ máy phát điện nhằm đảm bảo vận hành an toàn","Cả 3 câu trên đều sai"],ans:0,explain:"AGC là hệ thống tự động điều chỉnh tăng giảm công suất tác dụng của tổ máy phát điện, NMĐ, cụm NMĐ hoặc hệ thống pin tích trữ."},
{id:172,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng người nhận lệnh không cần phải xác định rõ họ tên, chức danh người ra lệnh?",opts:["Không cho phép","Thao tác thực hiện theo phiếu thao tác do nhà máy lập","Thao tác thay đổi công suất tổ máy","Thao tác thay đổi điện áp máy phát"],ans:2,explain:"Khi thao tác thay đổi công suất tổ máy, người nhận lệnh không cần xác định rõ họ tên người ra lệnh."},
{id:173,q:"Theo TT06/2025/TT-BCT, Khi máy biến áp nhảy sự cố, Đơn vị QLVH không cần phải có văn bản xác nhận MBA đủ điều kiện vận hành theo phương án nào?",opts:["Bảo vệ dự phòng tác động","Bảo vệ so lệch tác động, kiểm tra phát hiện lỗi mạch nhị thứ và đã khắc phục","Bảo vệ hơi tác động, cần đưa ngay MBA vào vận hành, NVVH thông báo MBA đã được Giám đốc đơn vị đồng ý đưa trở lại vận hành","Phương án A, B"],ans:3,explain:"Không cần văn bản xác nhận khi bảo vệ dự phòng tác động (A) hoặc bảo vệ so lệch tác động do lỗi mạch nhị thứ đã khắc phục (B)."},
{id:174,q:"Theo TT06/2025/TT-BCT: Đơn vị nào có trách nhiệm tổ chức kiểm tra và cấp Chứng nhận vận hành cho các chức danh Điều độ viên miền:",opts:["Cục Điều tiết điện lực","Tập đoàn Điện lực Việt Nam","Cấp Điều độ Quốc gia","Cấp Điều độ miền"],ans:2,explain:"Cấp Điều độ Quốc gia có trách nhiệm tổ chức kiểm tra và cấp Chứng nhận vận hành cho Điều độ viên miền."},
{id:175,q:"Theo TT06/2025/TT-BCT: Người được cử đi đào tạo để được cấp Chứng nhận vận hành trước khi sát hạch công nhận chức danh Trưởng kíp trạm điện có tuổi đời không quá bao nhiêu tuổi?",opts:["25 tuổi.","30 tuổi.","35 tuổi.","Không quy định"],ans:3,explain:"TT06 không quy định giới hạn tuổi đời cho người được cử đi đào tạo để cấp Chứng nhận vận hành Trưởng kíp."},
{id:176,q:"Theo TT06/2025/TT-BCT: Đóng điện đường dây, trình tự đóng máy cắt đầu đường dây nếu hai đầu đều có điện theo phương án nào?",opts:["Đóng máy cắt phía gần nguồn điện trước","Đóng máy cắt phía xa nguồn điện trước","Tùy theo tình hình thực tế","Không quy định"],ans:0,explain:"Đóng điện đường dây khi cả hai đầu có điện thì đóng máy cắt phía gần nguồn điện trước."},
{id:177,q:"Theo TT06/2025/TT-BCT, đơn vị quản lý vận hành bao gồm:",opts:["Đơn vị phát điện","Đơn vị truyền tải điện","Đơn vị phân phối điện","Cả 3 đáp án A,B,C"],ans:3,explain:"Đơn vị quản lý vận hành bao gồm đơn vị phát điện, truyền tải điện và phân phối điện."},
{id:178,q:"Theo TT06/2025/TT-BCT, Nếu không có quy định riêng, máy biến áp được phép quá tải lâu dài bao nhiêu % nếu không bị quá áp?",opts:["2,5%","5%","7,5%","10%"],ans:1,explain:"MBA được phép quá tải lâu dài 5% nếu không bị quá áp."},
{id:179,q:"Theo TT06/2025/TT-BCT, Điều kiện để đóng lại đường cáp sau khi nhảy sự cố?",opts:["Đơn vị QLVH xác nhận đường cáp đủ tiêu chuẩn vận hành","Đơn vị QLVH xác định lỗi mạch nhị thứ và đã khắc phục được","Sau khi phân tích sự cố kết luận điểm sự cố nằm ngoài phạm vi đường cáp","Phương án A, B, C"],ans:3,explain:"Để đóng lại đường cáp sau sự cố, cần thỏa mãn một trong các điều kiện A, B hoặc C."},
{id:180,q:"Theo TT06/2025/TT-BCT, Nội dung nào không phải lệnh điều độ?",opts:["Thông báo phương thức vận hành","Yêu cầu gửi báo cáo vận hành","Thay đổi trị số rơ le bảo vệ và tự động hóa","Chuẩn y kiến nghị của nhân viên vận hành cấp dưới về vận hành thiết bị"],ans:1,explain:"Yêu cầu gửi báo cáo vận hành không phải là lệnh điều độ, đây là yêu cầu hành chính."},
{id:181,q:"Theo TT06/2025/TT-BCT: Quy định về viết bổ sung các bước thao tác có liên quan đến thao tác mạch nhị thứ đúng theo phương án nào?",opts:["NVVH tại nhà máy yêu cầu đơn vị cấp phiếu phải lập phiếu thao tác mới và ghi thêm các thao tác bổ sung mạch nhị thứ","Đơn vị quản lý vận hành quy định","NVVH tại nhà máy phải lập phiếu thao tác mới, ghi thêm các thao tác bổ sung mạch nhị thứ dưới các hạng mục thao tác nhất thứ","NVVH tại nhà máy ghi thêm các thao tác bổ sung mạch nhị thứ dưới các hạng mục thao tác nhất thứ tại phiếu thao tác do Cấp điều độ có quyền điều khiển cấp"],ans:3,explain:"NVVH tại nhà máy ghi thêm các thao tác mạch nhị thứ dưới các hạng mục thao tác nhất thứ tại phiếu thao tác do Cấp điều độ cấp."},
{id:182,q:"Theo TT06/2025/TT-BCT, Máy biến áp phải tách ra khỏi vận hành khi thiếu rơ le bảo vệ trong trường hợp nào?",opts:["Bảo vệ so lệch","Bảo vệ hơi","Bảo vệ còn lại không bảo đảm chống mọi dạng sự cố","Phương án A, B"],ans:2,explain:"MBA phải tách khỏi vận hành khi bảo vệ còn lại không đảm bảo chống mọi dạng sự cố."},
{id:183,q:"Theo TT06/2025/TT-BCT: Khi truyền đạt lệnh thao tác bằng lời nói, lệnh thao tác phải được?",opts:["Ghi âm.","Chép đầy đủ vào sổ nhật ký vận hành tại các đơn vị","A hoặc B","Cả A & B"],ans:3,explain:"Lệnh thao tác bằng lời nói phải được cả ghi âm (A) và chép đầy đủ vào sổ nhật ký vận hành (B)."},
{id:184,q:"Theo TT05/2025/TT-BCT, hệ thống điện vận hành ở chế độ khẩn cấp khi xuất hiện hiện tượng nào:",opts:["Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp từ 90% trở lên nhưng không vượt quá giá trị định mức","Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp trên 90% nhưng không vượt quá giá trị định mức","Mức mang tải của bất kỳ thiết bị điện nào trong lưới điện cao áp, siêu cao áp vượt quá giá trị định mức nhưng dưới 110% giá trị định mức mà thiết bị này khi bị sự cố do quá tải có thể dẫn đến chế độ vận hành cực kỳ khẩn cấp","Cả A,B,C đều sai"],ans:2,explain:"Chế độ khẩn cấp khi mức mang tải vượt quá định mức nhưng dưới 110% mà thiết bị khi bị sự cố có thể gây ra chế độ cực kỳ khẩn cấp."},
{id:185,q:"Theo TT06/2025/TT-BCT: Phương án nào không cho phép hòa đồng bộ ở cấp điện áp 220kV theo điều kiện góc lệch pha?",opts:["Góc lệch pha điện áp giữa hai phía điểm hoà là 20 độ","Góc lệch pha điện áp giữa hai phía điểm hoà là 25 độ","Góc lệch pha điện áp giữa hai phía điểm hoà là 30 độ","Góc lệch pha điện áp giữa hai phía điểm hoà là 35 độ"],ans:3,explain:"Góc lệch pha 35 độ vượt quá giới hạn 30 độ cho phép, không được hòa đồng bộ."},
{id:186,q:"Theo TT06/2025/TT-BCT: Thao tác đóng điện máy biến áp mới khác với đóng điện MBA sau sửa chữa ở điểm nào?",opts:["Nấc máy biến áp đặt phù hợp với điện áp lưới điện, đảm bảo không bị quá điện áp khi đóng điện","Lựa chọn cấp điện áp thích hợp đóng điện máy biến áp","Đóng điện theo phiếu thao tác đã được phê duyệt","Kiểm tra đúng thứ tự pha và đồng vị pha"],ans:3,explain:"MBA mới phải kiểm tra đúng thứ tự pha và đồng vị pha trước khi đóng điện lần đầu - đây là điểm khác biệt với MBA sau sửa chữa."},
{id:187,q:"Theo TT06/2025/TT-BCT, máy biến áp dầu được phép quá tải ngắn hạn 45% trong bao lâu?",opts:["120 phút","80 phút","45 phút","20 phút"],ans:1,explain:"Quá tải ngắn hạn 45% cho phép 80 phút."},
{id:188,q:"Theo TT06/2025/TT-BCT, Phương án nào không đúng theo nguyên tắc lập sơ đồ kết dây cơ bản trong hệ thống điện:",opts:["Bảo đảm tính chọn lọc của rơ le bảo vệ","Đảm bảo khai thác tối đa nguồn điện rẻ tiền","Bảo đảm dòng ngắn mạch không vượt quá giá trị cho phép","Linh hoạt, thuận tiện trong thao tác và xử lý sự cố"],ans:1,explain:"'Đảm bảo khai thác tối đa nguồn điện rẻ tiền' không phải là nguyên tắc lập sơ đồ kết dây cơ bản."},
{id:189,q:"Theo TT06/2025/TT-BCT, Việc khôi phục cấp điện cho khách hàng sử dụng điện phải căn cứ theo thứ tự ưu tiên đã được Cơ quan nào xác định:",opts:["Các Tổng Công ty Điện lực","Uỷ ban nhân dân tỉnh, thành phố trực thuộc Trung ương","Tập đoàn Điện lực Việt Nam","Cấp Điều độ phân phối"],ans:1,explain:"Thứ tự ưu tiên khôi phục cấp điện do Uỷ ban nhân dân tỉnh, thành phố trực thuộc Trung ương xác định."},
{id:190,q:"Theo TT06/2025/TT-BCT: Quy định bậc an toàn đối với người thao tác trực tiếp và người giám sát tại vị trí đặt thiết bị điện nhất thứ:",opts:["Người thao tác trực tiếp phải có bậc an toàn từ bậc 02 trở lên, người giám sát phải có bậc an toàn từ bậc 03 trở lên","Người thao tác trực tiếp phải có bậc an toàn từ bậc 02 trở lên, người giám sát phải có bậc an toàn từ bậc 04 trở lên","Người thao tác trực tiếp phải có bậc an toàn từ bậc 03 trở lên, người giám sát phải có bậc 05 an toàn","Người thao tác trực tiếp phải có bậc an toàn từ bậc 03 trở lên, người giám sát phải có bậc an toàn từ bậc 04 trở lên"],ans:3,explain:"Người thao tác trực tiếp: bậc 03 trở lên; người giám sát: bậc 04 trở lên."},
{id:191,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định không đúng thời gian phiếu thao tác theo kế hoạch phải được chuyển tới nhân viên vận hành trực tiếp thao tác?",opts:["120 phút","90 phút","45 phút","30 phút"],ans:2,explain:"45 phút là không đúng vì phiếu thao tác theo kế hoạch phải chuyển trước ít nhất 90 phút (không phải 45 phút)."},
{id:192,q:"Theo TT06/2025/TT-BCT, Trường hợp nào sau đây phải tách máy biến áp ra khỏi vận hành:",opts:["Chảy dầu","Mẫu dầu không đạt tiêu chuẩn","Nhiệt độ cuộn dây quá mức cảnh báo","Có tiếng kêu khác thường"],ans:1,explain:"Mẫu dầu không đạt tiêu chuẩn là điều kiện bắt buộc phải tách MBA khỏi vận hành."},
{id:193,q:"Theo TT06/2025/TT-BCT, thời gian gửi báo cáo vận hành ngày tại nhà máy điện, trạm điện hoặc trung tâm điều khiển:",opts:["Trước 5h30","Trước 6h00","Trước 6h30","Trước 7h00"],ans:1,explain:"Báo cáo vận hành ngày phải gửi trước 6h00 theo TT06."},
{id:194,q:"Theo TT06/2025/TT-BCT: Phương án nào cho phép khép vòng cấp điện áp 220kV theo điều kiện về điện áp?",opts:["Chênh lệch điện áp giữa hai phía điểm hoà là 11 kV","Chênh lệch điện áp giữa hai phía điểm hoà là 22 kV","Chênh lệch điện áp giữa hai phía điểm hoà là 25 kV","Phương án A, B"],ans:3,explain:"Cho phép khép vòng 220kV khi chênh lệch điện áp ≤ 22 kV (phương án A và B đều thỏa mãn điều kiện, nên đáp án là D - cả A và B)."},
{id:195,q:"Theo TT06/2025/TT-BCT: Cho phép kiểm tra trạng thái máy cắt theo chỉ thị của tín hiệu tại phòng điều khiển mà không cần kiểm tra tại chỗ trong trường hợp?",opts:["Sau khi thao tác máy cắt, không thao tác dao cách ly hai phía của máy cắt này","Sau khi thao tác máy cắt, việc thao tác dao cách ly hai phía máy cắt được thực hiện bằng điều khiển từ xa","Thực hiện thao tác xa hoặc thao tác trong điều kiện thời tiết xấu","A hoặc B hoặc C"],ans:3,explain:"Được phép kiểm tra qua chỉ thị tín hiệu mà không cần kiểm tra tại chỗ trong các trường hợp A, B hoặc C."},
{id:196,q:"Theo TT06/2025/TT-BCT, ĐVQLVH thiết bị phải thực hiện thử nghiệm, kiểm tra và xác nhận thiết bị đủ tiêu chuẩn vận hành nếu thiết bị được tách dự phòng (không mang điện) trong thời gian bao lâu:",opts:["Quá 90 ngày","Quá 80 ngày","Quá 30 ngày","Quá 45 ngày"],ans:0,explain:"Thiết bị được tách dự phòng không mang điện quá 90 ngày thì phải thử nghiệm, kiểm tra xác nhận đủ tiêu chuẩn trước khi đưa vào vận hành."},
{id:197,q:"Theo TT06/2025/TT-BCT, nhân viên vận hành không bao gồm:",opts:["Điều độ viên tại các cấp điều độ","Nhân viên trực thao tác lưu động","Trưởng ca nhà máy điện","Quản đốc phân xưởng vận hành nhà máy điện"],ans:3,explain:"Quản đốc phân xưởng vận hành nhà máy điện không phải là nhân viên vận hành theo định nghĩa TT06."},
{id:198,q:"Theo TT05/2025/TT-BCT, quy định về thời gian chịu đựng tối thiểu của thiết bị (s) ở các cấp điện áp:",opts:["0.5 s","01 s","02 s","03 s"],ans:1,explain:"Thời gian chịu đựng tối thiểu của thiết bị ở các cấp điện áp là 01 giây."},
{id:199,q:"Theo TT06/2025/TT-BCT: Thao tác nào dưới đây không cần ghi chép vào sổ nhật ký vận hành?",opts:["Thay đổi nấc phân áp","Thay đổi công suất tổ máy","Thay đổi điện áp máy phát","Mọi thao tác phải được ghi nhận"],ans:3,explain:"Mọi thao tác đều phải được ghi chép vào sổ nhật ký vận hành."},
{id:200,q:"Theo TT06/2025/TT-BCT, Việc cô lập hoặc đưa các rơ le bảo vệ và tự động vào vận hành trở lại chỉ được thực hiện khi có mệnh lệnh cho phép của:",opts:["Điều độ viên cấp điều độ có quyền điều khiển.","Điều độ viên cấp điều độ có quyền kiểm tra.","Lãnh đạo đơn vị quản lý vận hành.","Lãnh đạo cấp điều độ có quyền điều khiển."],ans:0,explain:"Cô lập hoặc đưa rơ le bảo vệ vào vận hành trở lại phải có lệnh của Điều độ viên cấp điều độ có quyền điều khiển."},
{id:201,q:"Theo TT06/2025/TT-BCT, yêu cầu khi thực hiện lệnh điều độ bằng lời nói:",opts:["nêu rõ tên và chức danh trong mọi liên hệ bằng lời nói","nêu chức danh trong mọi liên hệ bằng lời nói","không cần nêu tên và chức danh","Không có đáp án nào đúng"],ans:0,explain:"Khi thực hiện lệnh điều độ bằng lời nói phải nêu rõ tên và chức danh trong mọi liên hệ."},
{id:202,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng trình tự thao tác chuyển điểm đấu từ thanh cái này sang thanh cái khác?",opts:["Không quy định","Lựa chọn bước thao tác theo thứ tự ngăn lộ theo sơ đồ đánh số thiết bị","Lựa chọn bước thao tác hợp lý để tránh quá tải máy cắt liên lạc","Lựa chọn bước thao tác theo phiếu thao tác mẫu"],ans:2,explain:"Trình tự thao tác chuyển điểm đấu phải lựa chọn hợp lý để tránh quá tải máy cắt liên lạc."},
{id:203,q:"Theo TT06/2025/TT-BCT, Nhà máy đủ điều kiện làm nhà máy khởi động đen chính:",opts:["Đấu nối vào cấp điện áp 500kV và có thời gian khởi động đen là 20 phút","Đấu nối vào cấp điện áp 220kV và có thời gian khởi động đen là 15 phút","Đấu nối vào cấp điện áp 110kV và có thời gian khởi động đen là 10 phút","Không phương án nào đúng"],ans:3,explain:"Không có phương án nào đủ điều kiện làm nhà máy khởi động đen chính theo quy định TT06."},
{id:204,q:"Theo TT06/2025/TT-BCT, điện áp thanh cái 220kV thuộc TBA 500kV do cấp điều độ nào điều khiển?",opts:["Cấp điều độ Quốc gia","Cấp điều độ miền","Cấp điều độ quốc gia và cấp điều độ miền","Trưởng kíp TBA 500kV"],ans:0,explain:"Điện áp thanh cái 220kV thuộc TBA 500kV do Cấp điều độ Quốc gia điều khiển."},
{id:205,q:"Theo TT06/2025/TT-BCT, Đơn vị nào có trách nhiệm xác định các vị trí quan trọng trong hệ thống điện quốc gia phải xây dựng các nhà máy điện có khả năng khởi động đen?",opts:["Tập đoàn Điện lực Việt Nam","Tổng Công ty Truyền tải điện Quốc gia","Cục Điều tiết Điện lực","Điều độ Quốc gia"],ans:3,explain:"Điều độ Quốc gia có trách nhiệm xác định các vị trí quan trọng cần xây dựng nhà máy có khả năng khởi động đen."},
{id:206,q:"Theo TT06/2025/TT-BCT: Phương án nào không đúng theo quy định trình tự thao tác dao cách ly hai phía máy cắt?",opts:["Mở dao cách ly phía không có điện áp trước","Đóng dao cách ly phía có điện áp trước","Mở dao cách ly phía nếu có sự cố xảy ra ít ảnh hưởng đến chế độ vận hành của hệ thống điện trước","Đóng dao cách ly phía nếu có sự cố xảy ra ít ảnh hưởng đến chế độ vận hành của hệ thống điện trước"],ans:0,explain:"Quy định đúng là mở dao cách ly phía ít ảnh hưởng trước (C), không phải mở phía không có điện áp trước."},
{id:207,q:"Theo TT06/2025/TT-BCT: Nếu cần thay đổi nội dung thao tác trong phiếu thao tác để phù hợp với sơ đồ kết dây thực tế, trường hợp nào là đúng?",opts:["Phải được sự đồng ý của người viết phiếu.","Phải được sự đồng ý của người ra lệnh.","Phải được sự đồng ý của người duyệt phiếu và phải ghi vào mục 'Các sự kiện bất thường trong thao tác' của phiếu thao tác và sổ nhật ký vận hành.","Phải được sự đồng ý của Điều độ cấp trên và phải ghi vào mục 'Các sự kiện bất thường trong thao tác' của phiếu thao tác và sổ nhật ký vận hành."],ans:2,explain:"Phải được sự đồng ý của người duyệt phiếu và ghi vào mục 'Các sự kiện bất thường trong thao tác'."},
{id:208,q:"Theo TT06/2025/TT-BCT: Việc đóng cắt thử máy cắt được thực hiện khi đảm bảo yêu cầu sau?",opts:["Nếu đóng dao cách ly một phía của máy cắt, phải cắt tất cả các tiếp địa của ngăn máy cắt này và lưu ý các mạch liên động, tự động được trang bị kèm","Các dao cách ly hai phía của máy cắt được cắt hoàn toàn và chỉ đóng dao tiếp địa hoặc tiếp địa di động ở một phía máy cắt này","Các dao cách ly hai phía của máy cắt được cắt hoàn toàn và phải đóng dao tiếp địa hoặc tiếp địa di động ở cả hai phía của máy cắt này","A hoặc B"],ans:3,explain:"Việc đóng cắt thử máy cắt được phép theo điều kiện A hoặc B (đóng dao cách ly một phía hoặc cắt cả 2 phía đóng tiếp địa 1 phía)."},
{id:209,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định không đúng trách nhiệm ban hành quy trình vận hành và xử lý sự cố?",opts:["Cấp điều độ có quyền điều khiển ban hành quy trình vận hành và xử lý sự cố trạm điện, nhà máy điện","Đơn vị quản lý vận hành ban hành quy trình vận hành và xử lý sự cố trạm điện, nhà máy điện","Cấp điều độ có quyền điều khiển ban hành quy trình vận hành và xử lý sự cố hệ thống điện thuộc quyền điều khiển","Đơn vị quản lý vận hành ban hành quy trình vận hành và xử lý sự cố hệ thống điện tự dùng"],ans:0,explain:"Cấp điều độ không ban hành quy trình vận hành trạm điện, nhà máy điện - đây là trách nhiệm của ĐVQLVH."},
{id:210,q:"Theo TT05/2025/TT-BCT, quy định về độ tin cậy tác động của hệ thống rơ le bảo vệ:",opts:["Không nhỏ hơn 99%","Không nhỏ hơn 98%","Không nhỏ hơn 95%","Không nhỏ hơn 90%"],ans:0,explain:"Độ tin cậy tác động của hệ thống rơ le bảo vệ không nhỏ hơn 99%."},
{id:211,q:"Theo TT06/2025/TT-BCT, Quy định về tách đường dây, thiết bị điện được thực hiện theo lệnh hoặc khi có sự cho phép của cấp điều độ có quyền điều khiển trong những trường hợp nào:",opts:["Khi nghe thông tin từ người dân báo đe doạ đến tính mạng con người","Đe dọa ổn định của hệ thống điện","Điện áp hệ thống điện vượt ra ngoài phạm vi quy định","B và C đúng"],ans:3,explain:"Tách thiết bị theo lệnh cấp điều độ khi đe dọa ổn định hệ thống điện (B) hoặc điện áp vượt ra ngoài phạm vi (C)."},
{id:212,q:"Theo TT06/2025/TT-BCT, Phương án nào cho phép khôi phục ngay đường dây 220 kV sau sự cố?",opts:["Đường dây sự cố 3 pha, tự động đóng lại không thành công","Đường dây sự cố 1 pha qua khu vực đông dân cư, tự động đóng lại không thành công","Đường dây sự cố 1 pha, đang bão có gió cấp 06","Phương án A, B"],ans:2,explain:"Đường dây 220kV sự cố 1 pha và đang có bão từ cấp 6 trở lên - không cho phép khôi phục ngay; các trường hợp còn lại theo điều kiện riêng."},
{id:213,q:"Theo TT06/2025/TT-BCT, hình thức lệnh điều độ?",opts:["Lời nói","Chữ viết","Tín hiệu điều khiển trực tiếp thiết bị điện thuộc quyền điều khiển","Cả 3 đáp án trên đều đúng"],ans:3,explain:"Lệnh điều độ có 3 hình thức: lời nói, chữ viết, và tín hiệu điều khiển trực tiếp."},
{id:214,q:"Theo TT06/2025/TT-BCT, điều nào sau đây không đúng về quyền điều khiển của nhà máy điện:",opts:["Tổ máy phát của nhà máy điện","Hệ thống tự dùng của nhà máy điện","Lưới điện thuộc sở hữu của nhà máy điện cung cấp điện cho khách hàng mua điện trực tiếp từ nhà máy điện","Các thiết bị phụ trợ không nối hệ thống điện quốc gia"],ans:1,explain:"Hệ thống tự dùng của nhà máy điện KHÔNG thuộc quyền điều khiển của cấp điều độ."},
{id:215,q:"Theo TT06/2025/TT-BCT: Quy định trình tự đầu tiên khi tách máy biến áp:",opts:["Chuyển nguồn tự dùng","Cắt máy cắt, dao cách ly các phía máy biến áp theo quy định","Kiểm tra trào lưu công suất qua máy biến áp","Cấp điều độ có quyền điều khiển ra lệnh thao tác"],ans:3,explain:"Trình tự đầu tiên khi tách MBA là cấp điều độ có quyền điều khiển ra lệnh thao tác."},
{id:216,q:"Theo TT06/2025/TT-BCT, Trường hợp nào sau đây phải tách MBA ra khỏi vận hành:",opts:["Theo quy định của Cấp điều độ có quyền điều khiển","Theo yêu cầu của đơn vị quản lý vận hành","Theo quy định của nhà sản xuất","Cả 3 đáp án trên"],ans:3,explain:"MBA phải tách khỏi vận hành theo yêu cầu từ cả 3 nguồn: cấp điều độ, ĐVQLVH, và nhà sản xuất."},
{id:217,q:"Theo TT05/2025/TT-BCT, Phương án nào hệ thống điện vận hành ở chế độ cực kỳ khẩn cấp?",opts:["Tần số hệ thống 48,9 Hz","Máy biến áp 110 kV đang mang tải là 109%","Điện áp thấp nhất trên lưới 220 kV là 195 kV","Phương án A, C"],ans:0,explain:"Tần số hệ thống 48,9 Hz vượt ra ngoài dải tần số cho phép là dấu hiệu chế độ cực kỳ khẩn cấp."},
{id:218,q:"Theo TT06/2025/TT-BCT, Mức giới hạn truyền tải đường dây trên không được xác định không đúng theo giới hạn nào?",opts:["Giới hạn phát nhiệt của dây dẫn hoặc thiết bị điện nối tiếp trên đường dây.","Giới hạn góc truyền tải theo điều kiện ổn định.","Giới hạn theo điện áp thấp -10% điện áp danh định.","Giới hạn dòng điện theo loại dây dẫn do Đơn vị quản lý vận hành quy định."],ans:2,explain:"'Giới hạn theo điện áp thấp -10% điện áp danh định' không phải là giới hạn truyền tải đường dây trên không."},
{id:219,q:"Theo TT06/2025/TT-BCT: Phương án nào quy định đúng khi người thao tác phát hiện có điều không hợp lý trong phiếu thao tác do điều độ miền lập?",opts:["Đề nghị người ra lệnh giải thích","Đề nghị người viết phiếu giải thích","Đề nghị người duyệt phiếu giải thích","Phương án A hoặc C"],ans:3,explain:"Khi phát hiện điều không hợp lý trong phiếu thao tác, đề nghị người ra lệnh (A) hoặc người duyệt phiếu (C) giải thích."},
{id:220,q:"Theo TT06/2025/TT-BCT: Phương án nào không cho phép hòa đồng bộ cấp điện áp 220kV theo điều kiện về điện áp?",opts:["Chênh lệch điện áp giữa hai phía điểm hoà là 20 kV","Chênh lệch điện áp giữa hai phía điểm hoà là 21 kV","Chênh lệch điện áp giữa hai phía điểm hoà là 22 kV","Chênh lệch điện áp giữa hai phía điểm hoà là 23 kV"],ans:3,explain:"Chênh lệch điện áp 23 kV vượt quá giới hạn cho phép 22 kV, không được hòa đồng bộ."},
{id:221,q:"Theo TT05/2025/TT-BCT, quy định về độ lệch điện áp vận hành cho phép trên lưới điện 500kV ở chế độ vận hành bình thường:",opts:["± 05 %","± 04 %","± 03 %","± 02 %"],ans:0,explain:"Độ lệch điện áp cho phép trên lưới 500kV ở chế độ bình thường là ± 5%."},
{id:222,q:"Theo TT06/2025/TT-BCT, Khi MBA bị cắt sự cố do bảo vệ so lệch và hơi (hoặc dòng dầu, áp lực dầu), được đưa MBA vào vận hành sau khi thực hiện đầy đủ các bước nào?",opts:["Tiến hành thí nghiệm, kiểm tra thử nghiệm các thông số, phân tích mẫu dầu, khắc phục những nhược điểm bất thường đã phát hiện; có văn bản xác nhận MBA đủ điều kiện vận hành gửi Cấp điều độ có quyền điều khiển.","Tiến hành thí nghiệm, thử nghiệm RLBV, phân tích mẫu khí, mẫu dầu, khắc phục những nhược điểm bất thường đã phát hiện; có văn bản xác nhận MBA đủ điều kiện vận hành gửi Cấp điều độ có quyền điều khiển.","Tiến hành thí nghiệm, kiểm tra thử nghiệm các thông số, phân tích mẫu khí, mẫu dầu, khắc phục những nhược điểm bất thường đã phát hiện; có văn bản xác nhận MBA đủ điều kiện vận hành gửi ĐĐV có quyền điều khiển.","Tiến hành thí nghiệm, kiểm tra thử nghiệm các thông số, phân tích mẫu khí, mẫu dầu, khắc phục những nhược điểm bất thường đã phát hiện; có văn bản xác nhận MBA đủ điều kiện vận hành gửi Cấp điều độ có quyền điều khiển."],ans:3,explain:"Phải thí nghiệm, kiểm tra thông số, phân tích mẫu khí VÀ mẫu dầu, khắc phục bất thường; có văn bản xác nhận gửi Cấp điều độ (không phải ĐĐV cá nhân)."},
{id:223,q:"Theo TT05/2025/TT-BCT, hệ thống điện vận hành ở chế độ cực kỳ khẩn cấp khi xuất hiện hiện tượng nào:",opts:["Mức mang tải của bất kỳ thiết bị nào trong lưới điện cao áp, siêu cao áp hoặc thiết bị đấu nối với lưới điện cao áp, siêu cao áp từ 110% giá trị định mức trở lên mà thiết bị này khi bị sự cố do quá tải có thể dẫn đến tan rã từng phần hệ thống điện;","Mức mang tải của các đường dây và MBA trong lưới điện cao áp, siêu cao áp trên 90% nhưng không vượt quá giá trị định mức","Mức mang tải của bất kỳ thiết bị điện nào trong lưới điện cao áp, siêu cao áp vượt quá giá trị định mức nhưng dưới 110% giá trị định mức mà thiết bị này khi bị sự cố do quá tải có thể dẫn đến chế độ vận hành cực kỳ khẩn cấp","Cả A,B,C đều sai"],ans:0,explain:"Chế độ cực kỳ khẩn cấp khi mức mang tải từ 110% giá trị định mức trở lên mà khi sự cố có thể gây tan rã từng phần hệ thống điện."},
{id:224,q:"Theo TT06/2025/TT-BCT: Thời gian lưu trữ của các phiếu thao tác thực hiện xong được quy định là bao nhiêu lâu?",opts:["Ít nhất 03 tháng","Ít nhất 06 tháng","Ít nhất 01 năm","Ít nhất 05 năm"],ans:2,explain:"Phiếu thao tác thực hiện xong lưu trữ ít nhất 01 năm theo TT06."},
{id:225,q:"Theo TT06/2025/TT-BCT, Phương án nào không phải là nhiệm vụ của cấp Điều độ miền:",opts:["Tham gia lập phương án khởi động đen và khôi phục HTĐ QG có cấp điện áp 220kV","Lập phương án khởi động đen và khôi phục HTĐ QG có cấp điện áp 110kV thuộc quyền điều khiển","Tham gia lập phương án khởi động đen và khôi phục HTĐ QG có cấp điện áp 22kV","Phương án A&C"],ans:3,explain:"Cả A (tham gia lập phương án 220kV) và C (tham gia 22kV) đều không phải nhiệm vụ của cấp điều độ miền."},
{id:226,q:"Theo TT06/2025/TT-BCT, Trường hợp nào sau đây phải xử lý đường dây theo chế độ cực kỳ khẩn cấp:",opts:["Đường dây mang tải trên 90%","Đường dây mang tải trên 100%","Đường dây mang tải trên 110%","Đáp án B và C"],ans:2,explain:"Xử lý chế độ cực kỳ khẩn cấp khi đường dây mang tải trên 110%."},
{id:227,q:"Theo TT06/2025/TT-BCT, nhân viên vận hành được làm những điều nào sau đây trong thời gian trực ca:",opts:["uống một chút bia","làm việc riêng","Cho kỹ sư CNTT & SCADA vào phòng điều khiển để xử lý lỗi hệ thống SCADA trường hợp được sự đồng ý của lãnh đạo trực tiếp.","Cả 3 đáp án đều sai"],ans:2,explain:"NVVH có thể cho kỹ sư CNTT & SCADA vào phòng điều khiển khi được sự đồng ý của lãnh đạo trực tiếp."},
{id:228,q:"Theo TT05/2025/TT-BCT, quy định về lưới điện truyền tải:",opts:["Phần lưới điện bao gồm toàn bộ các đường dây và trạm điện có cấp điện áp trên 22kV","Phần lưới điện bao gồm toàn bộ các đường dây và trạm điện có cấp điện áp trên 110kV","Phần lưới điện bao gồm toàn bộ các đường dây và trạm điện có cấp điện áp trên 220kV","Không có đáp án đúng"],ans:1,explain:"Lưới điện truyền tải bao gồm toàn bộ đường dây và trạm điện có cấp điện áp trên 110kV."},
{id:229,q:"Theo TT06/2025/TT-BCT, Khi sự cố đường dây trên 35kV đến 220kV qua khu dân cư, chỉ được phép đóng lại đường dây lần thứ 2 trong trường hợp nào?",opts:["Đóng lại theo lệnh NVVH cấp trên","Sau khi ĐVQLVH đã thực hiện kiểm tra, xác nhận đường dây đủ điều kiện vận hành và đảm bảo an toàn cho người, thiết bị điện.","Xin ý kiến lãnh đạo để đóng lại","Không đóng lại, cô lập đường dây bàn giao ĐVQLVH sửa chữa"],ans:1,explain:"Chỉ được đóng lại lần 2 sau khi ĐVQLVH kiểm tra, xác nhận đường dây đủ điều kiện vận hành và đảm bảo an toàn."},
{id:230,q:"Theo TT06/2025/TT-BCT, thứ tự điều chỉnh điện áp:",opts:["Thay đổi nguồn công suất phản kháng của tụ điện, kháng điện, máy bù đồng bộ, máy bù tĩnh, máy phát điện theo thứ tự từ gần đến xa điểm cần điều chỉnh điện áp.","Thay đổi nguồn công suất phản kháng của tụ điện, kháng điện, máy bù đồng bộ, máy bù tĩnh, máy phát điện theo thứ tự từ xa đến gần điểm cần điều chỉnh điện áp.","Không quy định","Cả 3 đáp án đều sai"],ans:0,explain:"Thứ tự điều chỉnh điện áp: từ gần đến xa điểm cần điều chỉnh, theo thứ tự tụ điện, kháng điện, máy bù đồng bộ, máy bù tĩnh, máy phát điện."},
{id:231,q:"Theo TT05/2025/TT-BCT, Phương án nào hệ thống điện vận hành không ở chế độ cảnh báo?",opts:["Tần số hệ thống 49,5 Hz","Máy biến áp chính 220 kV đang mang tải là 95%","Điện áp thấp nhất trên lưới 220kV là 210kV","Phương án A, C"],ans:3,explain:"Tần số 49,5 Hz (nằm ngoài dải bình thường) và điện áp 210kV trên lưới 220kV đều không phải là chỉ báo chế độ cảnh báo."},
{id:232,q:"Theo TT05/2025/TT-BCT, quy định về khởi động nhanh:",opts:["Tổ máy phát điện, NMĐ cung cấp dự phòng khởi động nhanh phải có khả năng tăng đến công suất định mức trong vòng 25 phút và duy trì tối thiểu 08 giờ","Tổ máy phát điện, NMĐ cung cấp dự phòng khởi động nhanh phải có khả năng tăng đến công suất định mức trong vòng 30 phút và duy trì tối thiểu 07 giờ","Tổ máy phát điện, NMĐ cung cấp dự phòng khởi động nhanh phải có khả năng tăng đến công suất định mức trong vòng 35 phút và duy trì tối thiểu 06 giờ","Tổ máy phát điện, NMĐ cung cấp dự phòng khởi động nhanh phải có khả năng tăng đến công suất định mức trong vòng 40 phút và duy trì tối thiểu 05 giờ"],ans:0,explain:"Dự phòng khởi động nhanh phải tăng đến công suất định mức trong vòng 25 phút và duy trì tối thiểu 08 giờ."},
{id:233,q:"Theo TT06/2025/TT-BCT: Thời gian đào tạo Trưởng kíp tại trạm điện:",opts:["ít nhất 03 tháng.","ít nhất 06 tháng.","ít nhất 09 tháng.","ít nhất 12 tháng."],ans:1,explain:"Thời gian đào tạo Trưởng kíp tại trạm điện ít nhất 06 tháng."},
{id:234,q:"Theo TT06/2025/TT-BCT, thứ tự ưu tiên khi thực hiện lệnh điều độ bằng lời nói:",opts:["Kênh trực thông hoặc kênh vô tuyến - điện thoại cố định - điện thoại di động","Điện thoại di động - kênh trực thông hoặc kênh vô tuyến - điện thoại cố định","Điện thoại cố định - Điện thoại di động - kênh trực thông hoặc kênh vô tuyến","Không có đáp án nào đúng"],ans:0,explain:"Thứ tự ưu tiên: kênh trực thông/vô tuyến → điện thoại cố định → điện thoại di động."},
{id:235,q:"Theo TT06/2025/TT-BCT: Quyền điều khiển của Cấp điều độ miền:",opts:["Công suất phát của nhà máy điện có tổng công suất đặt từ 30 MW trở lên","Công suất phát của nhà máy điện có tổng công suất đặt từ 30 MW trở xuống","Công suất phát của nhà máy điện có tổng công suất đặt từ 30 MW trở xuống đấu nối vào lưới điện có cấp điện áp 110kV, 220kV","Công suất phát của nhà máy điện có tổng công suất đặt trên 30 MW đấu nối vào lưới điện có cấp điện áp 110kV, 220kV thuộc hệ thống điện miền"],ans:3,explain:"Cấp điều độ miền có quyền điều khiển công suất phát của NMĐ có tổng công suất đặt TRÊN 30 MW đấu nối vào lưới 110kV, 220kV thuộc hệ thống điện miền."},
{id:236,q:"Theo TT06/2025/TT-BCT: Thời gian đào tạo Trưởng kíp tại trung tâm điều khiển trạm điện:",opts:["ít nhất 03 tháng.","ít nhất 06 tháng.","ít nhất 09 tháng.","ít nhất 12 tháng."],ans:1,explain:"Thời gian đào tạo Trưởng kíp tại trung tâm điều khiển trạm điện ít nhất 06 tháng."},
{id:237,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định đúng không cho phép khôi phục đường dây 220kV khi có bão đi qua?",opts:["Với gió giật từ cấp 10 trở lên","Với gió từ cấp 6 trở lên","Với gió từ cấp 10 trở lên","Với gió giật từ cấp 6 trở lên"],ans:0,explain:"Không cho phép khôi phục đường dây 220kV khi bão có gió giật từ cấp 10 trở lên."},
{id:238,q:"Theo TT06/2025/TT-BCT, quy định về biểu đồ điện áp do đơn vị nào ban hành:",opts:["Cấp điều độ có quyền điều khiển ban hành","Trung tâm điều độ hệ thống điện miền ban hành","EVN ban hành","Do đơn vị quản lý vận hành tự ban hành"],ans:0,explain:"Biểu đồ điện áp do Cấp điều độ có quyền điều khiển ban hành."},
{id:239,q:"Theo TT06/2025/TT-BCT: khi cắt điện đường dây phải thao tác máy cắt như thế nào:",opts:["Thao tác máy cắt xa nguồn điện trước, gần nguồn điện sau","Thao tác máy cắt gần nguồn điện trước, xa nguồn điện sau","Thao tác máy cắt nào trước cũng được","Thao tác để thuận tiện cho trình tự cắt điện đường dây"],ans:1,explain:"Khi cắt điện đường dây, thao tác máy cắt gần nguồn điện trước, xa nguồn điện sau."},
{id:240,q:"Theo TT06/2025/TT-BCT: Quy định đúng điều kiện cho phép khép mạch vòng trên hệ thống điện?",opts:["Đồng tần, đồng áp, đồng pha","Góc lệch pha điện áp không quá 15 độ, chênh lệch điện áp không quá 10%","Góc lệch pha điện áp không quá 30 độ, chênh lệch điện áp không quá 5%","Góc lệch pha điện áp không quá 30 độ, chênh lệch điện áp không quá 10%"],ans:3,explain:"Điều kiện khép mạch vòng: góc lệch pha ≤ 30 độ, chênh lệch điện áp ≤ 10%."},
{id:241,q:"Theo TT05/2025/TT-BCT, quy định về dòng điện ngắn mạch lớn nhất cho phép (kA) cấp 500kV:",opts:["50","55","60","45"],ans:0,explain:"Dòng điện ngắn mạch lớn nhất cho phép ở cấp 500kV là 50 kA."},
{id:242,q:"Theo TT06/2025/TT-BCT: Hạn chế thực hiện thao tác vào thời điểm nào?",opts:["Giờ có nhu cầu sử dụng điện cao","Chuẩn bị giao nhận ca","Xử lý sự cố","Phương án A, B"],ans:3,explain:"Hạn chế thực hiện thao tác vào giờ có nhu cầu sử dụng điện cao (A) và chuẩn bị giao nhận ca (B)."},
{id:243,q:"Theo TT06/2025/TT-BCT, Khi lệnh của Lãnh đạo trực tiếp trái với lệnh của Nhân viên vận hành cấp trên?",opts:["Nhân viên vận hành cấp dưới thi hành lệnh của Lãnh đạo trực tiếp và báo cáo Nhân viên vận hành cấp trên","Nhân viên vận hành cấp dưới có quyền không thi hành lệnh của Lãnh đạo trực tiếp và báo cáo Nhân viên vận hành cấp trên.","Đưa ra những lý do không chấp hành với Lãnh đạo trực tiếp, nếu Lãnh đạo trực tiếp không chấp thuận thì vẫn thi hành mệnh lệnh sau đó báo cáo lên Nhân viên vận hành cấp trên.","Nhân viên vận hành cấp dưới có quyền không thi hành lệnh của Lãnh đạo trực tiếp và báo cáo Nhân viên vận hành cấp trên, trừ trường hợp có nguy cơ đe dọa đến tính mạng con người và an toàn thiết bị"],ans:3,explain:"NVVH cấp dưới có quyền không thi hành lệnh lãnh đạo trực tiếp nếu trái với lệnh cấp trên, trừ khi có nguy cơ đe dọa tính mạng và an toàn thiết bị."},
{id:244,q:"Theo TT06/2025/TT-BCT, quy định nhiệm vụ của trưởng kíp trạm điện hoặc trung tâm điều khiển trạm điện:",opts:["Chấp hành lệnh điều độ của nhân viên vận hành cấp trên","Thường xuyên theo dõi thông số vận hành và kiểm tra thiết bị thuộc quyền quản lý của trạm điện","Nắm vững sơ đồ, thông số kỹ thuật, phương thức vận hành, quy trình vận hành và quy trình xử lý sự cố thiết bị trong trạm điện","Cả 3 đáp an A, B, C đều đúng"],ans:3,explain:"Trưởng kíp có cả 3 nhiệm vụ: chấp hành lệnh, theo dõi thông số, và nắm vững quy trình."},
{id:245,q:"Theo TT06/2025/TT-BCT: trách nhiệm bảo đảm hoạt động ổn định, tin cậy của hệ thống rơ le bảo vệ và tự động hóa thuộc phạm vi quản lý thuộc về đơn vị nào?",opts:["Các cấp điều độ","Đơn vị truyền tải điện","EVN","Cả 3 đáp án trên đều đúng"],ans:3,explain:"Trách nhiệm bảo đảm hoạt động ổn định, tin cậy của RLBV và tự động hóa thuộc về tất cả các đơn vị: cấp điều độ, đơn vị truyền tải, và EVN."},
{id:246,q:"Theo TT06/2025/TT-BCT, Đối với trường hợp gió cấp 06 trở lên, Điều độ viên chủ động cho khóa tự đóng lại của các máy cắt đường dây ở cấp điện áp nào:",opts:["Siêu cao áp","Cao áp","Trung áp","Không quy định"],ans:1,explain:"Khi gió cấp 06 trở lên, Điều độ viên chủ động khóa tự đóng lại của máy cắt đường dây ở cấp cao áp."},
{id:247,q:"Theo TT06/2025/TT-BCT: Trình tự thực hiện Kiểm tra và cấp chứng nhận vận hành cho các chức danh tham gia trực tiếp công tác điều độ, vận hành hệ thống điện quốc gia do đơn vị nào có trách nhiệm xây dựng:",opts:["Bộ Công Thương.","Cục Điều tiết điện lực.","Tập Đoàn Điện lực.","Đơn vị Điều độ hệ thống điện quốc gia."],ans:3,explain:"Đơn vị Điều độ hệ thống điện quốc gia có trách nhiệm xây dựng trình tự kiểm tra và cấp chứng nhận vận hành."},
{id:248,q:"Theo TT06/2025/TT-BCT, Đơn vị QLVH có trách nhiệm cung cấp danh sách các đường dây đi qua khu vực tập trung đông người, khu dân cư cho ai?",opts:["Cho đơn vị phát điện","Cho cấp điều độ có quyền kiểm tra","Cho cấp điều độ có quyền điều khiển","Cho đơn vị mua bán điện"],ans:2,explain:"ĐVQLVH cung cấp danh sách đường dây qua khu dân cư cho cấp điều độ có quyền điều khiển."},
{id:249,q:"Theo TT06/2025/TT-BCT: Khi thực hiện sửa chữa nóng đường dây trên không phải thực hiện biện pháp an toàn theo phương án nào?",opts:["Đơn vị công tác tự làm biện pháp an toàn","Đơn vị quản lý vận hành tự làm biện pháp an toàn","Đơn vị điều độ ra lệnh cô lập mạch tự động đóng lại đường dây trong thời gian công tác sửa chữa nóng","Nhân viên vận hành tại trạm điện, nhà máy điện tự chuyển khóa tự đóng lại sang vị trí OFF"],ans:2,explain:"Khi sửa chữa nóng đường dây, đơn vị điều độ phải ra lệnh cô lập mạch tự động đóng lại đường dây trong thời gian công tác."},
{id:250,q:"Theo TT05/2025/TT-BCT, Hệ thống điện vận hành ở chế độ cảnh báo khi:",opts:["Mức mang tải của các đường dây và MBA trong lưới điện từ 110kV trở lên trên 110% giá trị định mức","Mức mang tải của các đường dây và MBA trong lưới điện từ 110kV trở lên vượt quá giá trị định mức nhưng dưới 110%","Mức độ mang tải của các đường dây và MBA trong lưới điện từ 110kV trở lên trên 90% nhưng không vượt quá giá trị định mức.","Mức độ mang tải của các đường dây và MBA trong lưới điện từ 110kV trở lên trên 90%."],ans:2,explain:"Chế độ cảnh báo khi mức mang tải từ 90% trở lên nhưng không vượt quá giá trị định mức."},
{id:251,q:"Theo TT06/2025/TT-BCT, các bộ phận trực tiếp tham gia công tác điều độ hệ thống điện miền gồm:",opts:["Trực ban chỉ huy điều độ miền","Phương thức ngắn hạn","Phương thức dài hạn","Cả 3 đáp án A, B, C đều đúng"],ans:3,explain:"Các bộ phận trực tiếp tham gia điều độ hệ thống điện miền gồm cả 3: Trực ban chỉ huy điều độ miền, Phương thức ngắn hạn, Phương thức dài hạn."},
{id:252,q:"Theo TT06/2025/TT-BCT, quy định về lập phương thức vận hành hệ thống điện thuộc quyền điều khiển dịp lễ, tết và những ngày có yêu cầu đặc biệt là trách nhiệm của:",opts:["Bộ phận phương thức dài hạn","Bộ phận phương thức ngắn hạn","Bộ phận trực ban chỉ huy điều độ miền","Không quy định"],ans:1,explain:"Lập phương thức vận hành dịp lễ, tết là trách nhiệm của bộ phận phương thức ngắn hạn."},
{id:253,q:"Theo TT06/2025/TT-BCT: Đơn vị QLVH giao máy biến áp cho cấp điều độ có quyền điều khiển để đưa vào vận hành bao gồm nội dung gì?",opts:["Không cần giao nhận máy biến áp","Đã kết thúc công tác, người và phương tiện sửa chữa đã rút hết khỏi máy biến áp","Đã tháo hết tiếp địa di động trên máy biến áp, máy biến áp đủ tiêu chuẩn vận hành và sẵn sàng đóng điện","Phương án B, C"],ans:3,explain:"Giao MBA phải xác nhận đủ cả: đã rút hết người và phương tiện (B) VÀ đã tháo tiếp địa di động, MBA đủ tiêu chuẩn và sẵn sàng đóng điện (C)."},
{id:254,q:"Theo TT06/2025/TT-BCT: Hình thức chuyển phiếu thao tác giữa các đơn vị tham gia thao tác thực hiện không cho phép theo hình thức nào?",opts:["Đọc qua điện thoại","Chuyển qua thư điện tử","Chuyển trực tiếp","Chuyển qua tin nhắn"],ans:3,explain:"Không cho phép chuyển phiếu thao tác qua tin nhắn. Chỉ cho phép: đọc qua điện thoại, chuyển qua thư điện tử, hoặc chuyển trực tiếp."},
{id:255,q:"Theo TT06/2025/TT-BCT, Đơn vị QLVH phải gửi Báo cáo sự cố cho Cấp điều độ có quyền điều khiển?",opts:["Ngay sau khi xử lý xong sự cố.","Trong vòng 24 giờ kể từ khi sự cố xảy ra.","Trong vòng 48 giờ kể từ khi sự cố xảy ra.","Không cần gửi báo cáo nếu đã báo cáo qua điện thoại"],ans:1,explain:"ĐVQLVH phải gửi Báo cáo sự cố trong vòng 24 giờ kể từ khi sự cố xảy ra."},
{id:256,q:"Theo TT06/2025/TT-BCT: Khi cần thiết, cho phép được cắt sự cố thêm đối với các máy cắt đã có tổng dòng cắt ngắn mạch hoặc số lần cắt ngắn mạch đến mức quy định, với điều kiện?",opts:["Đã kiểm tra máy cắt đủ tiêu chuẩn vận hành","Được sự đồng ý của Giám đốc hoặc Phó giám đốc kỹ thuật Đơn vị QLVH","Được sự đồng ý của cấp điều độ có quyền điều khiển","Cả A và B"],ans:3,explain:"Để cắt sự cố thêm khi vượt mức quy định, cần đáp ứng cả 2 điều kiện: kiểm tra MC đủ tiêu chuẩn (A) VÀ được sự đồng ý của Giám đốc/Phó Giám đốc kỹ thuật (B)."},
{id:257,q:"Theo TT06/2025/TT-BCT, Lựa chọn phương án đúng trong điều kiện vận hành bình thường của máy biến áp:",opts:["Được vận hành 05 tiếng khi điện áp cao hơn điện áp định mức 7% và tải MBA là 90%","Được vận hành 02 tiếng khi điện áp cao hơn điện áp định mức 11% và tải MBA là 20%","Được vận hành lâu dài khi điện áp cao hơn điện áp định mức 6% và tải MBA là 30%","Không phương án nào đúng"],ans:2,explain:"MBA được vận hành lâu dài khi điện áp cao hơn định mức 6% (≤ 10%) và tải không quá 30% công suất định mức."},
{id:258,q:"Theo TT06/2025/TT-BCT, Trong trường hợp nào Điều độ viên được phép khôi phục lại đường cáp điện lực sau khi nhảy sự cố?",opts:["ĐVQLVH kiểm tra, xác nhận đường cáp đủ tiêu chuẩn vận hành hoặc xác định đường cáp bị cắt điện sự cố là do lỗi mạch nhị thứ và đã được khắc phục.","Được phép khôi phục ngay sau sự cố","Sau khi phân tích sự cố bảo vệ rơ le tác động là do ngắn mạch thoáng qua ngoài phạm vi đường cáp.","A hoặc C"],ans:3,explain:"Được phép khôi phục đường cáp khi ĐVQLVH xác nhận đủ tiêu chuẩn hoặc lỗi mạch nhị thứ đã khắc phục (A) hoặc khi xác định ngắn mạch thoáng qua ngoài phạm vi cáp (C)."},
{id:259,q:"Theo TT06/2025/TT-BCT: Cắt điện đường dây, trình tự cắt máy cắt đầu đường dây theo phương án nào?",opts:["Cắt máy cắt phía gần nguồn điện trước","Cắt máy cắt phía xa nguồn điện trước","Tùy theo tình hình thực tế","Không quy định"],ans:1,explain:"Khi cắt điện đường dây, cắt máy cắt phía xa nguồn điện trước, sau đó cắt phía gần nguồn điện."},
{id:260,q:"Theo TT06/2025/TT-BCT, quy định nhân viên bộ phận trực ban chỉ huy điều độ miền:",opts:["Không được ít hơn 4 người, trong đó phải có 2 Điều độ viên phụ trách","Không được ít hơn 4 người, trong đó phải có 1 Điều độ viên phụ trách","Không được ít hơn 3 người, trong đó phải có 1 Điều độ viên phụ trách","Không được ít hơn 2 người, trong đó phải có 1 Điều độ viên phụ trách"],ans:0,explain:"Bộ phận trực ban chỉ huy điều độ miền không được ít hơn 4 người, trong đó phải có 2 Điều độ viên phụ trách."},
{id:261,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định không đúng nguyên tắc xử lý sự cố:",opts:["Áp dụng mọi biện pháp để nhanh chóng loại trừ sự cố","Nhanh chóng khôi phục việc cung cấp điện cho khách hàng","Vận hành hệ thống điện với tần số và điện áp khác với chế độ vận hành bình thường","Nhanh chóng khôi phục hệ thống điện về trạng thái vận hành bình thường"],ans:2,explain:"'Vận hành hệ thống điện với tần số và điện áp khác với chế độ bình thường' KHÔNG phải là nguyên tắc xử lý sự cố, mà cần phải đưa về bình thường."},
{id:262,q:"Theo TT06/2025/TT-BCT, Điều độ viên miền phải lập Báo cáo sự cố phần tử thuộc quyền điều khiển theo phương án nào:",opts:["Không phải lập báo cáo sự cố","Không quy định","Theo mẫu quy định tại Quy trình vận hành và xử lý sự cố hệ thống điện do Cấp điều độ quốc gia ban hành","Theo mẫu quy định tại Phụ lục VIII ban hành kèm theo Thông tư trên"],ans:2,explain:"Điều độ viên miền lập Báo cáo sự cố theo mẫu quy định tại Quy trình vận hành và xử lý sự cố do Cấp điều độ quốc gia ban hành."},
{id:263,q:"Theo TT05/2025/TT-BCT, quy định về độ lệch điện áp vận hành cho phép trên lưới điện 220kV so với điện áp danh định ở chế độ vận hành bình thường:",opts:["+ 10 % và - 05%","+ 10 % và - 10%","+ 5 % và - 05%","+ 3 % và - 05%"],ans:0,explain:"Độ lệch điện áp trên lưới 220kV ở chế độ bình thường: + 10% và - 5% so với điện áp danh định."},
{id:264,q:"Theo TT06/2025/TT-BCT: Trường hợp cần chỉnh sửa phiếu thao tác, ĐĐV phải hỏi ý kiến của ai:",opts:["Người viết phiếu","Trưởng, phó phòng Điều độ","Người duyệt phiếu","ĐĐV phụ trách ca trực"],ans:2,explain:"Khi cần chỉnh sửa phiếu thao tác, ĐĐV phải hỏi ý kiến của người duyệt phiếu."},
{id:265,q:"Theo TT06/2025/TT-BCT: Thao tác đóng điện đường dây mới khác với đóng điện đường dây sau sửa chữa ở điểm nào?",opts:["Dùng máy cắt và rơ le bảo vệ dự phòng đã được chỉnh định để đóng điện đường dây lần đầu","Khoá mạch tự động đóng lại đường dây trước khi đóng điện lần đầu","Kiểm tra điều kiện khép vòng hoặc hòa đồng bộ đầu còn lại trước khi đóng khép vòng hoặc hoà hai hệ thống","Đóng điện đường dây theo phiếu thao tác đã được phê duyệt"],ans:1,explain:"Điểm khác biệt khi đóng điện đường dây mới: phải khóa mạch tự động đóng lại (TĐLL) trước khi đóng điện lần đầu."},
{id:266,q:"Theo TT06/2025/TT-BCT, Khi sự cố đường cáp và đường dây hỗn hợp 220kV, cho phép đóng lại đường dây và cáp này bao nhiêu lần?",opts:["Đóng lại một lần","Không đóng lại ngay, chỉ đóng lại khi có yêu cầu từ Đơn vị quản lý vận hành","Xin ý kiến lãnh đạo để đóng lại một lần","Không đóng lại, cô lập đường dây bàn giao Đơn vị quản lý vận hành sửa chữa"],ans:1,explain:"Khi sự cố đường cáp và đường dây hỗn hợp 220kV, không đóng lại ngay, chỉ đóng lại khi có yêu cầu từ ĐVQLVH."},
{id:267,q:"Theo TT06/2025/TT-BCT: Phương án nào cho phép hòa đồng bộ cấp điện áp 220kV theo điều kiện về tần số?",opts:["Chênh lệch tần số giữa hai phía điểm hoà là 0,10 Hz","Chênh lệch tần số giữa hai phía điểm hoà là 0,15 Hz","Chênh lệch tần số giữa hai phía điểm hoà là 0,25 Hz","Phương án A, B, C"],ans:3,explain:"Điều kiện về tần số cho hòa đồng bộ 220kV: chênh lệch tần số ≤ 0,25 Hz, nên tất cả A (0,10), B (0,15), C (0,25) đều thỏa mãn."},
{id:268,q:"Theo TT06/2025/TT-BCT: Quy định trách nhiệm của Nhân viên vận hành trực ban trung gian khi truyền lệnh?",opts:["Phải ghi âm, ghi chép lệnh đầy đủ vào sổ và chuyển ngay lệnh đến đúng người nhận lệnh","Phải chuyển ngay lệnh đến đúng người nhận lệnh. Nếu không liên lạc được với người nhận lệnh, phải báo lại ngay cho người ra lệnh biết","Phải ghi âm, ghi chép lệnh đầy đủ vào sổ và chuyển ngay lệnh đến đúng người nhận lệnh. Nếu không liên lạc được với người nhận lệnh, phải báo lại ngay cho người ra lệnh biết","Không quy định"],ans:2,explain:"NVVH trực ban trung gian phải ghi âm, ghi chép lệnh, chuyển ngay đến người nhận lệnh, và nếu không liên lạc được phải báo ngay cho người ra lệnh."},
{id:269,q:"Theo TT06/2025/TT-BCT, Phương án nào quy định đúng trách nhiệm ngăn ngừa sự cố lan rộng?",opts:["Đơn vị quản lý vận hành","Cấp điều độ có quyền điều khiển","Nhân viên vận hành","Phương án A, B, C"],ans:3,explain:"Trách nhiệm ngăn ngừa sự cố lan rộng thuộc về tất cả: ĐVQLVH, cấp điều độ có quyền điều khiển, và nhân viên vận hành."},
{id:270,q:"Theo TT05/2025/TT-BCT, yêu cầu đối với CT sử dụng cho mục đích đo đếm điện năng:",opts:["Giá trị dòng điện thứ cấp danh định là 01A hoặc 05A","Giá trị dòng điện thứ cấp danh định là 02A hoặc 06A","Giá trị dòng điện thứ cấp danh định là 03A hoặc 09A","không quy định"],ans:0,explain:"CT dùng cho đo đếm điện năng phải có giá trị dòng điện thứ cấp danh định là 01A hoặc 05A."},
{id:271,q:"Theo TT06/2025/TT-BCT: Trình tự thao tác đóng dao cách ly hai phía máy cắt khi một phía có điện áp, một phía không có điện áp?",opts:["Đóng dao cách ly phía không có điện áp trước","Đóng dao cách ly phía có điện áp trước","Đóng dao cách ly phía nào trước cũng được","Đóng dao cách ly phía có điện áp sau"],ans:1,explain:"Khi đóng dao cách ly, đóng phía có điện áp trước để điện áp không xuất hiện bất ngờ ở phía chưa đóng."},
{id:272,q:"Theo TT06/2025/TT-BCT: Thao tác xa là thao tác?",opts:["Do NVVH tại các cấp điều độ hoặc Trung tâm điều khiển gửi tín hiệu điều khiển từ xa để thay đổi trạng thái hoặc thông số vận hành các thiết bị điện trên đường dây, trạm điện, nhà máy điện qua hệ thống điều khiển và hệ thống thông tin, viễn thông","Do NVVH tại trạm, nhà máy điều khiển gửi tín hiệu điều khiển từ xa để thay đổi trạng thái hoặc thông số vận hành các thiết bị điện tại trạm điện, nhà máy điện","Cả A & B","Không phương án nào đúng"],ans:0,explain:"Thao tác xa là do NVVH tại các cấp điều độ hoặc Trung tâm điều khiển gửi tín hiệu để thay đổi trạng thái/thông số vận hành thiết bị điện qua hệ thống điều khiển và viễn thông."},
{id:273,q:"Theo TT06/2025/TT-BCT: Trong quá trình thao tác nếu có cảnh báo, trục trặc, bất thường, nhân viên vận hành phải thực hiện theo phương án nào?",opts:["Báo cáo lãnh đạo đơn vị, xin ý kiến chỉ đạo","Báo cáo người ra lệnh biện pháp xử lý tình huống","Ngừng thao tác, xử lý xong mới thao tác tiếp","Phương án A, B"],ans:1,explain:"Khi có cảnh báo bất thường trong thao tác, phải báo cáo người ra lệnh để được biết biện pháp xử lý tình huống."},
];
